                "payload_mutation": {"set": {}, "remove": [removable_key]},
                "meta_mutations": [{"op": "remove", "path": f"validation.runtime_params.{removable_key}"}],
                "allow_captured_message_fallback": False,
                "description": f"移除字段 {removable_key}，检查本地是否还能重建请求。",
