@register_operation("hmac_sha256")
class HMACSha256Operation(CryptoOperation):
    """HMAC-SHA256 签名"""

    def __init__(self):
        super().__init__("hmac_sha256")

    def execute(self, context: CryptoContext) -> HandlerResult:
        try:
            key = context.key or context.extra_params.get("key")
            if not key:
                return HandlerResult(success=False, error="Missing key for HMAC")

            plaintext = context.plaintext
            if isinstance(plaintext, dict):
                plaintext = json.dumps(plaintext, separators=(',', ':'), sort_keys=True)
            if isinstance(plaintext, str):
                plaintext = plaintext.encode(context.input_encoding)

            # HMAC Key usually string in JS context, NOT Hex bytes
            # JS: CryptoJS.HmacSHA256("Message", "Secret Passphrase")
            if isinstance(key, str):
                key = key.encode('utf-8')
            elif isinstance(key, bytes):
                pass
            else:
                key = str(key).encode('utf-8')

            signature = hmac.new(key, plaintext, hashlib.sha256).digest()

            # Fix: Default/Force Hex for HMAC (CryptoJS default toString is Hex)
            output = signature.hex()

            return HandlerResult(success=True, output=output, context=context)

        except Exception as e:
            return HandlerResult(success=False, error=str(e))


# =============================================================================
# Encoding
# =============================================================================


@register_operation("base64_encode")
class Base64EncodeOperation(CryptoOperation):
    """Base64 编码"""

    def __init__(self):
        super().__init__("base64_encode")

    def execute(self, context: CryptoContext) -> HandlerResult:
        try:
            data = context.plaintext
            if isinstance(data, str):
                data = data.encode(context.input_encoding)

            output = base64.b64encode(data).decode('ascii')
            return HandlerResult(success=True, output=output, context=context)

        except Exception as e:
            return HandlerResult(success=False, error=str(e))


@register_operation("hex_encode")
class HexEncodeOperation(CryptoOperation):
    """Hex 编码"""

    def __init__(self):
        super().__init__("hex_encode")

    def execute(self, context: CryptoContext) -> HandlerResult:
        try:
            data = context.plaintext
            if isinstance(data, str):
                data = data.encode(context.input_encoding)

            output = data.hex()
            return HandlerResult(success=True, output=output, context=context)

        except Exception as e:
            return HandlerResult(success=False, error=str(e))


@register_operation("variable_derivation")
class VariableDerivationOperation(CryptoOperation):
    """变量衍生逻辑执行器 (用于 Key/IV 动态生成)"""

    def __init__(self):
        super().__init__("variable_derivation")

    def execute(self, context: CryptoContext) -> HandlerResult:
        try:
            target = context.extra_params.get("target") # "key" or "iv"
            derivation_rule = context.extra_params.get("derivation")
            base_payload = context.extra_params.get("base_payload", {})

            if not target or not derivation_rule:
                return HandlerResult(success=False, error="Missing target or derivation rule")

            # 如果运行时已注入 key/iv，验证阶段优先使用捕获值，避免被本地随机衍生覆盖
            if target == "key" and context.key is not None:
                context.logs.append("Derived key skipped: using injected runtime key")
                return HandlerResult(success=True, output=context.plaintext, context=context)
            if target == "iv" and context.iv is not None:
                context.logs.append("Derived iv skipped: using injected runtime iv")
                return HandlerResult(success=True, output=context.plaintext, context=context)

            # 递归计算
            resolved_value = self._evaluate(derivation_rule, base_payload)

            # 更新上下文
            if target == "key":
                context.key = resolved_value
            elif target == "iv":
                context.iv = resolved_value

            # Record log
            context.logs.append(f"Derived {target}: {str(resolved_value)[:20]}...")

            return HandlerResult(success=True, output=context.plaintext, context=context)

        except Exception as e:
            return HandlerResult(success=False, error=f"Derivation failed: {str(e)}")

    def _evaluate(self, node, payload):
        node_type = node.get("type")

        if node_type == "source":
            key_name = node.get("value")
            # 尝试从 payload 获取
            val = payload.get(key_name)
            if val is None:
                raise ValueError(f"Source variable '{key_name}' not found in payload")
            return val

        if node_type == "literal":
            return node.get("value")

        if node_type == "binary_op":
            op = node.get("op")
            left = self._evaluate(node.get("left"), payload)
            right = self._evaluate(node.get("right"), payload)

            if op == "+":
                return str(left) + str(right)
            else:
                raise ValueError(f"Unsupported binary op: {op}")

        if node_type == "op":
            op_method = node.get("op")
            input_val = self._evaluate(node.get("input"), payload)
            args_nodes = node.get("args", [])
            args = [self._evaluate(arg, payload) for arg in args_nodes]

            if op_method == "slice":
                start = int(args[0])
                end = int(args[1])
                return str(input_val)[start:end]

            if op_method == "padEnd":
                width = int(args[0])
                fillchar = str(args[1]) if len(args) > 1 else " "
                s = str(input_val)
                if len(s) >= width:
                    return s
                needed = width - len(s)
                padding = (fillchar * needed)[:needed]
                return s + padding

            if op_method == "toString":
                return str(input_val)

            if "Utf8.parse" in str(op_method) or "parse" in str(op_method):
                return str(input_val).encode('utf-8')

            raise ValueError(f"Unsupported operation: {op_method}")

        raise ValueError(f"Unknown node type: {node_type}")

#!/usr/bin/env python3
"""
Handler Pipeline
================
基于基线骨架 (Baseline Skeleton) 驱动的加密流水线执行器
"""

import base64
import json
import os
import random
from pathlib import Path
from typing import Dict, Any, List, Optional

from .base import CryptoContext, HandlerResult
from .registry import get_registry
from .validator import ValidationLayer  # Import ValidationLayer

class BaselinePipelineRunner:
    """
    基线驱动的流水线运行器

    解析 baseline_skeletons.json 中的 execution_flow，动态构建每个 API 的处理流水线。
    支持从文件加载多个骨架并批量执行验证。
    """

    def __init__(self, source: Any):
        """
        初始化运行器
        :param source: 可以是文件路径 (str/Path)、单个骨架字典 (dict) 或骨架列表 (list)
        """
        self.skeletons = []
        self.file_path = None
        self.registry = get_registry()

        if isinstance(source, (str, Path)):
            self.file_path = Path(source)
            if self.file_path.exists():
                with open(self.file_path, "r", encoding="utf-8") as f:
                    content = json.load(f)
                    if isinstance(content, list):
                        self.skeletons = content
                    elif isinstance(content, dict):
                        self.skeletons = [content]
        elif isinstance(source, list):
            self.skeletons = source
        elif isinstance(source, dict):
            self.skeletons = [source]

    def process_all(self, interactive: bool = False):
        """
        处理所有加载的基线骨架
        :param interactive: 是否启用交互式 Payload 输入
        """
        updated = False
        print(f"[*] Loaded {len(self.skeletons)} baseline entries.")

        for i, skeleton in enumerate(self.skeletons):
            meta = skeleton.get("meta", {})
            req = skeleton.get("request", {})
            val = skeleton.get("validation", {})
            runtime_params = val.get("runtime_params", {})
            endpoint_id = meta.get("id", f"entry_{i}")
            url = meta.get("url", "unknown")
            execution_flow = meta.get("execution_flow", [])

            print(f"\n>>> Processing Endpoint: {endpoint_id} ({url})")

            # 1. Check Payload
            payload = req.get("payload")
            if self._is_payload_missing(payload, runtime_params, execution_flow):
                print(f"[-] Payload missing or incomplete.")
                skeleton["status"] = "PENDING_PAYLOAD"
                if interactive:
                    hints = meta.get("hints", [])
                    print(f"    Hints: {hints}")
                    new_payload = self._prompt_payload()
                    if new_payload:
                        req["payload"] = new_payload
                        payload = new_payload
                        updated = True
                    else:
                        print("[-] Skipped.")
                        continue
                else:
                    print("[-] Skipped (Interactive mode disabled).")
                    continue

            # 2. Build Pipeline Steps & Context
            steps, flow_context = self._build_steps_and_context(execution_flow)

            # 3. Execution
            print("[*] Executing local handler...")

            # Merge context: global defaults + flow extracted (keys/ivs) + payload
            pipeline_context = {
                "endpoint_id": endpoint_id,
                "url": url,
                "base_payload": payload
            }
            pipeline_context.update(flow_context)

            pipeline_config = {
                "steps": steps,
                "context": pipeline_context
            }
            pipeline = HandlerPipeline(pipeline_config)

            # Inject capture runtime parameters (Keys, IVs, Nonces) to ensure deterministic reproduction
            if runtime_params:
                print(f"[*] Injecting runtime params: {list(runtime_params.keys())}")
                # Ensure we don't overwrite payload if it's there, though payload is 1st arg

            # 关键修复：仅当当前基线缺少结构化输入信息时，才回退使用捕获的 message。
            input_data = payload
            has_structured_inputs = any(
                step.get("input_expression") or step.get("input_derivation")
                for step in execution_flow
                if str(step.get("step_type", "")).lower() in ["encrypt", "sign"]
            )
            if not has_structured_inputs and "message" in runtime_params and runtime_params["message"]:
                 print(f"[*] 当前基线缺少结构化输入，回退使用 captured 'message' 作为验证输入")
                 input_data = runtime_params["message"]

            result = pipeline.execute(input_data, **runtime_params)

            if result.success:
                verification_output = self._select_verification_output(result, execution_flow)
                print(f"[+] Success. Output prefix: {str(verification_output)[:50]}...")
                val["handler_ciphertext"] = verification_output
                val["last_run"] = "success"
                val.pop("errors", None)
                skeleton["status"] = "HANDLER_EXECUTED"
                updated = True
            else:
                print(f"[-] Failed: {result.error}")
                val["last_run"] = "failed"
                val["errors"] = [result.error]
                skeleton["status"] = "HANDLER_FAILED"
                updated = True

            # 4. Verification (if captured ciphertext exists)
            captured = val.get("captured_ciphertext")

            # Check for non-crypto endpoints (PayloadPacking only)
            algos = meta.get("crypto_algorithms", [])
            is_encryption = any(algo not in ["PayloadPacking"] for algo in algos)

            if not is_encryption:
                print(f"[+] INFO: Endpoint performs Payload Packing only (No client-side crypto).")
                print(f"    Marking as VERIFIED.")
                val["verified"] = True
                val["comparison_result"] = "NO_CRYPTO"
                skeleton["status"] = "VERIFIED"
            elif captured:
                # Use ValidationLayer for robust comparison
                # We use self.file_path if available, otherwise fallback to empty path which ValidationLayer handles if it doesn't exist?
                # Actually ValidationLayer requires a path. self.file_path is usually set.
                validator_path = self.file_path if self.file_path else Path("dummy_non_existent.json")
                validator = ValidationLayer(validator_path)

                # Mock result for validation
                val_result = validator.validate_simple(captured, verification_output)

                # Check RSA/AESRSA context for relaxed validation
                algos = meta.get("crypto_algorithms", [])
                algos_str = [str(a).upper() for a in algos]
                is_rsa = "RSA" in algos_str or "AESRSA" in algos_str

                if val_result.matched:
                    print(f"[+] VERIFIED: Matches captured ciphertext ({val_result.matched_strategy}).")
                    val["verified"] = True
                    val["comparison_result"] = "MATCH"
                    skeleton["status"] = "VERIFIED"
                else:
                    if is_rsa:
                        print(f"[*] RSA Detected: Skipping strict ciphertext comparison (Random Padding).")
                        print(f"    Marking as VERIFIED (Logic Validated).")
                        val["verified"] = True
                        val["comparison_result"] = "RSA_NONDETERMINISTIC_LOGIC_VALIDATED"
                        skeleton["status"] = "VERIFIED"
                    else:
                        print(f"[-] MISMATCH: Does not match captured ciphertext.")
                        # print(f"    Expected: {captured}")
                        # print(f"    Actual:   {result.output}")
                        val["verified"] = False
                        val["comparison_result"] = "MISMATCH"
                        skeleton["status"] = "VERIFICATION_FAILED"
            else:
                if result.success:
                    skeleton["status"] = "READY"

        if updated and self.file_path:
            self._save()

    def _select_verification_output(self, result: HandlerResult, execution_flow: List[Dict]) -> Any:
        if not result or not result.success or not result.context:
            return result.output if result else None

        for step_info in reversed(execution_flow):
            step_type = str(step_info.get("step_type", "")).lower()
            if step_type not in ["encrypt", "sign"]:
                continue
            output_variable = step_info.get("output_variable")
            if output_variable:
                candidate = result.context.get_intermediate(output_variable)
                if candidate is not None:
                    return candidate
        return result.output

    def _save(self):
        with open(self.file_path, "w", encoding="utf-8") as f:
            json.dump(self.skeletons, f, indent=2, ensure_ascii=False)
        print(f"\n[+] Updated baseline file: {self.file_path}")

    def _is_payload_missing(
        self,
        payload: Any,
        runtime_params: Optional[Dict[str, Any]] = None,
        execution_flow: Optional[List[Dict[str, Any]]] = None,
    ) -> bool:
        if not payload:
            return True

        # 这些字段通常由运行时（hook 或 handler）回填，不要求用户在 payload 中手工填写
        runtime_fillable_fields = {
            "signature", "timestamp", "nonce", "random", "encryptedTimestamp"
        }
        runtime_params = runtime_params or {}

        # 由 execution_flow 自动生成/回填的字段：不要求用户手工填写。
        flow_fillable_fields = set(runtime_fillable_fields)
        for step in execution_flow or []:
            output_var = step.get("output_variable")
            if output_var:
                flow_fillable_fields.add(str(output_var))

            if str(step.get("step_type", "")).lower() == "pack":
                packing_info = (step.get("runtime_args", {}) or {}).get("packing_info", {}) or {}
                structure = packing_info.get("structure", {}) or {}
                for source_name in structure.values():
                    if source_name:
                        flow_fillable_fields.add(str(source_name))
                field_sources = packing_info.get("field_sources", {}) or {}
                if isinstance(field_sources, dict):
                    for _, source_meta in field_sources.items():
                        if isinstance(source_meta, dict) and source_meta.get("source_name"):
                            flow_fillable_fields.add(str(source_meta.get("source_name")))

        if isinstance(payload, dict):
            if "_comment" in payload:
                return True

            # 若字段是可运行时回填字段，且 runtime_params 中已有对应值，则不视为缺失
            for key, value in payload.items():
                if value != "<Fill Value>":
                    continue
                if key in flow_fillable_fields:
                    continue
                if key in runtime_fillable_fields and runtime_params.get(key) not in [None, "", "<Fill Value>"]:
                    continue
                return True

        return False

    def _prompt_payload(self) -> Optional[Dict]:
        print("Please enter valid JSON payload (or 's' to skip):")
        try:
            raw = input("JSON > ").strip()
            if raw.lower() == 's': return None
            return json.loads(raw)
        except Exception as e:
            print(f"[!] Invalid input: {e}")
            return None

    def _build_steps_and_context(self, execution_flow: List[Dict]):
        """
        根据 execution_flow 构建可执行的 steps 和 context params
        Returns: (steps, context_params)
        """
        steps = []
        context_params = {}

        # 遍历 execution_flow 中的原子操作
        for step_info in execution_flow:
            step_type = step_info.get("step_type", "").lower() # e.g., init, setkey, encrypt
            algorithm = step_info.get("algorithm", "")
            runtime_args = step_info.get("runtime_args", {})

            # 1. Context Setters: init, setkey, setiv, hardcoded_secret
            if step_type in ["init", "setkey", "setiv", "hardcoded_secret"]:
                if runtime_args:
                    context_params.update(runtime_args)
                continue

            # NEW: Variable Derivation (Key/IV)
            elif step_type.startswith("derive_"):
                # runtime_args contains "derivation"
                target = step_type.replace("derive_", "") # key or iv
                steps.append({
                    "operation": "variable_derivation",
                    "algorithm": "Derivation",
                    "params": {
                        "target": target,
                        "derivation": runtime_args.get("derivation")
                    }
                })
                continue

            # 2. Encrypt/Sign/Pack操作
            elif step_type in ["encrypt", "sign", "pack"]:
                # 特殊处理 pack：保留 packing_info，让流水线也能尝试组装请求体
                if step_type == "pack":
                     steps.append({
                         "operation": "payload_pack",
                         "algorithm": "PayloadPacking",
                         "params": runtime_args,
                         "packing_info": runtime_args.get("packing_info", {}),
                         "source_context": step_info.get("context", "")
                     })
                     continue

                operation_name = self._map_operation(algorithm, step_type)
                if operation_name:
                    step_config = {
                        "operation": operation_name,
                        "algorithm": algorithm,
                        "params": runtime_args
                    }
                    if step_info.get("output_variable"):
                        step_config["output_variable"] = step_info.get("output_variable")
                    if step_info.get("context"):
                        step_config["source_context"] = step_info.get("context")
                    if step_info.get("input_expression"):
                        step_config["input_expression"] = step_info.get("input_expression")
                    if step_info.get("input_derivation"):
                        step_config["input_derivation"] = step_info.get("input_derivation")
                    if step_info.get("input_source_keys"):
                        step_config["input_source_keys"] = step_info.get("input_source_keys")
                    if step_info.get("output_transform"):
                        step_config["output_transform"] = step_info.get("output_transform")
                    steps.append(step_config)

            # 3. 其他操作
            else:
                pass

        return steps, context_params

    def _build_steps(self, execution_flow: List[Dict]) -> List[Dict[str, Any]]:
        steps, _ = self._build_steps_and_context(execution_flow)
        return steps


    def _map_operation(self, algorithm: str, op_type: str) -> Optional[str]:
        """将算法+操作映射为 registry 中的 operation_name"""
        algo = algorithm.upper()
        op = op_type.lower()

        mapping = {
            "AES": {"encrypt": "aes_encrypt", "decrypt": "aes_decrypt"},
            "DES": {"encrypt": "des_encrypt", "decrypt": "des_decrypt"},
            "RSA": {"encrypt": "rsa_encrypt", "decrypt": "rsa_decrypt"},
            "HMACSHA256": {"sign": "hmac_sha256"},
            "HMACSHA256()": {"sign": "hmac_sha256"},
            "MD5": {"sign": "md5", "encrypt": "md5"}, # MD5通常叫hash，但也可能被标记为sign
            "SHA256": {"sign": "sha256", "encrypt": "sha256"},
            # 默认回退
            "UNKNOWN": {}
        }

        if algo in mapping and op in mapping[algo]:
            return mapping[algo][op]

        # 尝试通用命名
        potential_name = f"{algo.lower()}_{op}"
        if self.registry.get_operation(potential_name):
            return potential_name

        return None



class HandlerPipeline:
    """
    加密流水线 (Handler Pipeline)

    不再依赖独立的 YAML 配置文件，而是直接通过字典配置（来自基线 JSON 的 meta 信息）初始化。
    负责按顺序执行一系列加密或解密操作。
    """

    def __init__(self, config: Dict[str, Any]):
        """
        初始化流水线

        Args:
            config: 流水线配置字典
                {
                    "steps": [ ... ],       # 操作步骤列表
                    "context": { ... }      # 初始上下文 (endpoint_id, url 等)
                }
        """
        self.config = config
        self.registry = get_registry()
        self.steps = config.get("steps", [])
        self.global_context = config.get("context", {})

    def execute(self, input_data: Any, **extra_params) -> HandlerResult:
        """
        执行流水线

        Args:
            input_data: 初始输入数据（通常是 request.payload）
            **extra_params: 运行时注入的额外参数（如从 Hook 捕获的 Key/IV）

        Returns:
            HandlerResult: 包含最终结果和执行上下文
        """
        # 1. 初始化执行上下文
        context = self._build_context(input_data, extra_params)

        # 2. 依次执行每个步骤
        current_output = input_data
        context.logs.append(f"开始执行流水线，共 {len(self.steps)} 个步骤")

        for i, step in enumerate(self.steps):
            # 获取操作名称
            # 优先使用显式指定的 'operation'
            operation_name = step.get("operation")

            # 兼容旧逻辑：如果未指定 operation，尝试根据 algorithm + type 推断
            if not operation_name and "algorithm" in step:
                algo = step.get("algorithm", "").lower()
                # 默认为 encrypt，除非显式覆盖
                op_type = step.get("operation_type", "encrypt").lower()

                # 特殊处理：如果 step 有 "operation" 字段但不是标准名称（如 static analysis 中的 "encrypt"）
                if "operation" in step and step["operation"] in ["encrypt", "decrypt", "sign", "verify"]:
                     op_type = step["operation"].lower()

                operation_name = f"{algo}_{op_type}"

            if not operation_name:
                return HandlerResult(
                    success=False,
                    error=f"步骤 {i}: 缺少操作名称 (operation)",
                    context=context
                )

            # 3. 参数注入与上下文更新
            # 将步骤配置中的 params 合并入 context
            step_params = step.get("params", {})
            for key, value in step_params.items():
                if hasattr(context, key):
                   setattr(context, key, value)
                else:
                   context.extra_params[key] = value

            if operation_name == "payload_pack":
                try:
                    packed_output = self._build_packed_output(step, context, current_output)
                    current_output = packed_output
                    output_variable = step.get("output_variable")
                    if output_variable:
                        context.set_intermediate(output_variable, packed_output)
                    context.logs.append(f"步骤 {i} (payload_pack) 完成")
                    continue
                except Exception as e:
                    return HandlerResult(
                        success=False,
                        error=f"步骤 {i} (payload_pack) 执行异常: {str(e)}",
                        context=context
                    )

            # 获取操作类实例
            operation_class = self.registry.get_operation(operation_name)
            if not operation_class:
                return HandlerResult(
                    success=False,
                    error=f"步骤 {i}: 未知的操作 '{operation_name}'",
                    context=context
                )

            # 将步骤配置中的 details (来自静态分析) 尝试合入 context
            if "details" in step and isinstance(step["details"], list):
                 for detail_item in step["details"]:
                     if isinstance(detail_item, dict):
                         for k, v in detail_item.items():
                             if k not in ["operation", "line", "context"] and hasattr(context, k):
                                 setattr(context, k, v)

            # 设置当前步骤的输入数据
            resolved_input = self._resolve_step_input(step, context, current_output)
            context.plaintext = resolved_input

            # 4. 执行具体操作
            try:
                operation = operation_class()
                result = operation.execute(context)
            except Exception as e:
                return HandlerResult(
                    success=False,
                    error=f"步骤 {i} ({operation_name}) 执行异常: {str(e)}",
                    context=context
                )

            if not result.success:
                return HandlerResult(
                    success=False,
                    error=f"步骤 {i} ({operation_name}) 失败: {result.error}",
                    context=context
                )

            output_value = result.output
            if step.get("output_transform"):
                output_value = self._apply_output_transform(step.get("output_transform"), output_value, context)

            # 更新中间结果，准备下一步
            context.set_intermediate(f"step_{i}_output", output_value)
            output_variable = step.get("output_variable")
            if output_variable:
                context.set_intermediate(output_variable, output_value)
            current_output = output_value
            context.logs.append(f"步骤 {i} ({operation_name}) 完成")

        # 返回最终结果
        return HandlerResult(
            success=True,
            output=current_output,
            context=context,
            metadata={"steps_executed": len(self.steps)}
        )

    def _build_context(self, input_data: Any, extra_params: Dict) -> CryptoContext:
        """构建初始执行上下文"""
        context_params = {**self.global_context, **extra_params}
        context = CryptoContext(plaintext=input_data)

        for key, value in context_params.items():
            if hasattr(context, key):
                setattr(context, key, value)
            else:
                context.extra_params[key] = value

        context.extra_params.setdefault("runtime_params", dict(extra_params))
        return context

    def _resolve_step_input(self, step: Dict[str, Any], context: CryptoContext, current_output: Any) -> Any:
        input_expression = step.get("input_expression")
        input_derivation = step.get("input_derivation")
        runtime_params = context.extra_params.get("runtime_params", {}) or {}
        algorithm = str(step.get("algorithm", "")).upper()
        step_type = str(step.get("operation", "")).lower()

        # 对精确匹配最敏感的场景，优先使用浏览器真实捕获到的明文输入，避免字段顺序差异
        if input_expression in ["jsonData", "dataString", "formData", "dataToSend", "dataPacket"] and runtime_params.get("message"):
            return runtime_params.get("message")
        # HMAC/签名场景：dataToSign 往往包含 nonce/timestamp，优先使用浏览器捕获的原始拼接串。
        if input_expression in ["dataToSign", "signData", "signatureInput"] and runtime_params.get("message"):
            return runtime_params.get("message")
        if step_type == "hmac_sha256" and runtime_params.get("message"):
            return runtime_params.get("message")
        if algorithm == "DES" and input_expression == "password" and runtime_params.get("message"):
            return runtime_params.get("message")

        if input_expression:
            resolved = self._resolve_expression(input_expression, context, current_output)
            if resolved is not None:
                return resolved

        if input_derivation:
            resolved = self._evaluate_derivation(input_derivation, context, current_output)
            if resolved is not None:
                return resolved

        return current_output

    def _resolve_expression(self, expression: str, context: CryptoContext, current_output: Any) -> Any:
        expr = str(expression).strip()
        if not expr:
            return None

        if expr in context.intermediate_results:
            return context.get_intermediate(expr)

        runtime_params = context.extra_params.get("runtime_params", {}) or {}
        base_payload = context.extra_params.get("base_payload", {}) or {}

        if expr in base_payload:
            return base_payload[expr]
        if expr in runtime_params:
            return runtime_params[expr]
        if expr in ["jsonData", "dataString", "formData", "dataToSend", "dataPacket"]:
            if runtime_params.get("message"):
                return runtime_params.get("message")
            return json.dumps(base_payload, separators=(",", ":"), ensure_ascii=False)
        if expr.startswith("JSON.stringify(") and expr.endswith(")"):
            if runtime_params.get("message"):
                return runtime_params.get("message")
            inner = expr[len("JSON.stringify("):-1].strip()
            inner_val = self._resolve_expression(inner, context, current_output)
            if inner_val is None:
                return None
            if isinstance(inner_val, str):
                return inner_val
            return json.dumps(inner_val, separators=(",", ":"), ensure_ascii=False)
        if expr.endswith(".toString(CryptoJS.enc.Base64)"):
            base_name = expr.split(".", 1)[0]
            base_val = self._resolve_expression(base_name, context, current_output)
            if base_val is None:
                return None
            return base64.b64encode(self._coerce_bytes(base_val)).decode("ascii")
        if expr.endswith(".toString()"):
            base_name = expr.split(".", 1)[0]
            base_val = self._resolve_expression(base_name, context, current_output)
            if base_val is None:
                return None
            return str(base_val)
        if expr in ["key", "iv", "publicKey"]:
            lookup = {
                "key": context.key,
                "iv": context.iv,
                "publicKey": context.extra_params.get("public_key") or context.key
            }
            return lookup.get(expr)

        return None

    def _evaluate_derivation(self, node: Any, context: CryptoContext, current_output: Any) -> Any:
        if not isinstance(node, dict):
            return node

        node_type = node.get("type")
        runtime_params = context.extra_params.get("runtime_params", {}) or {}
        base_payload = context.extra_params.get("base_payload", {}) or {}

        if node_type == "source":
            key_name = node.get("value")
            if key_name in base_payload:
                return base_payload.get(key_name)
            return runtime_params.get(key_name)

        if node_type == "literal":
            return node.get("value")

        if node_type == "identifier":
            name = node.get("name")
            if name in context.intermediate_results:
                return context.get_intermediate(name)
            if name in base_payload:
                return base_payload.get(name)
            if name in runtime_params:
                return runtime_params.get(name)
            if name == "timestamp":
                return runtime_params.get("timestamp") or int(__import__("time").time())
            return None

        if node_type == "member_access":
            source_val = self._evaluate_derivation(node.get("input"), context, current_output)
            prop = node.get("property")
            if prop == "ciphertext":
                return source_val
            if isinstance(source_val, dict):
                return source_val.get(prop)
            return None

        if node_type == "binary_op":
            left = self._evaluate_derivation(node.get("left"), context, current_output)
            right = self._evaluate_derivation(node.get("right"), context, current_output)
            if node.get("op") == "+":
                return f"{'' if left is None else left}{'' if right is None else right}"
            return None

        if node_type == "call":
            callee = node.get("callee")
            args = [self._evaluate_derivation(arg, context, current_output) for arg in node.get("args", [])]
            expression = node.get("expression", "")
            if callee == "Math.random":
                if runtime_params.get("nonce"):
                    return f"0.{runtime_params.get('nonce')}"
                return random.random()
            if callee == "Math.floor":
                if "Date.now() / 1000" in expression:
                    return runtime_params.get("timestamp") or int(__import__("time").time())
                return int(args[0]) if args and isinstance(args[0], (int, float)) else None
            if callee == "Date.now":
                return runtime_params.get("timestamp") or int(__import__("time").time() * 1000)
            if callee == "CryptoJS.lib.WordArray.random":
                length = int(args[0]) if args else 16
                return os.urandom(length)
            return runtime_params.get(callee) or None

        if node_type == "op":
            input_val = self._evaluate_derivation(node.get("input"), context, current_output)
            args = [self._evaluate_derivation(arg, context, current_output) for arg in node.get("args", [])]
            op_name = node.get("op")

            if op_name == "JSON.stringify":
                if isinstance(input_val, str):
                    return input_val
                return json.dumps(input_val, separators=(",", ":"), ensure_ascii=False)
            if op_name == "toString":
                codec = args[0] if args else None
                if codec == "CryptoJS.enc.Base64":
                    return base64.b64encode(self._coerce_bytes(input_val)).decode("ascii")
                if codec == "CryptoJS.enc.Hex":
                    return self._coerce_bytes(input_val).hex()
                if isinstance(input_val, str) and args and args[0] == 36:
                    return input_val
                if isinstance(input_val, float) and args and args[0] == 36:
                    return str(input_val)
                return str(input_val)
            if op_name == "substring":
                start = int(args[0]) if len(args) > 0 and args[0] is not None else 0
                end = int(args[1]) if len(args) > 1 and args[1] is not None else None
                return str(input_val)[start:end]
            if op_name == "slice":
                start = int(args[0]) if len(args) > 0 and args[0] is not None else 0
                end = int(args[1]) if len(args) > 1 and args[1] is not None else None
                return str(input_val)[start:end]
            if op_name == "padEnd":
                width = int(args[0]) if len(args) > 0 and args[0] is not None else len(str(input_val))
                fillchar = str(args[1]) if len(args) > 1 and args[1] is not None else " "
                text = str(input_val)
                if len(text) >= width:
                    return text
                return text + (fillchar * (width - len(text)))[: width - len(text)]
            if op_name in ["Utf8.parse", "Hex.parse", "Base64.parse"]:
                return self._coerce_bytes(input_val)

        return None

    def _apply_output_transform(self, transform: str, output_value: Any, context: CryptoContext) -> Any:
        transform = str(transform)
        if ".toString(CryptoJS.enc.Hex)" in transform:
            if isinstance(output_value, str):
                candidate = output_value.strip().lower()
                if candidate and all(ch in "0123456789abcdef" for ch in candidate):
                    return output_value
            return self._coerce_bytes(output_value).hex()
        if ".toString(CryptoJS.enc.Base64)" in transform:
            if isinstance(output_value, str):
                return output_value
            return base64.b64encode(self._coerce_bytes(output_value)).decode("ascii")
        return output_value

    def _build_packed_output(self, step: Dict[str, Any], context: CryptoContext, current_output: Any) -> Any:
        packing_info = step.get("packing_info") or step.get("params", {}).get("packing_info") or {}
        packing_type = packing_info.get("type")
        structure = packing_info.get("structure", {}) or {}
        field_sources = packing_info.get("field_sources", {}) or {}
        value_derivations = packing_info.get("value_derivations", {}) or {}

        resolved_fields = {}
        for field_name, source_name in structure.items():
            value = None
            if source_name in context.intermediate_results:
                value = context.get_intermediate(source_name)
            elif source_name in (context.extra_params.get("runtime_params", {}) or {}):
                value = context.extra_params.get("runtime_params", {}).get(source_name)
            elif source_name in (context.extra_params.get("base_payload", {}) or {}):
                value = context.extra_params.get("base_payload", {}).get(source_name)
            elif field_name in field_sources and isinstance(field_sources[field_name], dict):
                field_source = field_sources[field_name]
                source_expr = str(field_source.get("source_expression", ""))
                source_var = field_source.get("source_name")
                bridge_var = field_source.get("bridge_from_output")
                bridge_transform = str(field_source.get("bridge_transform", "")).lower()
                if source_var in context.intermediate_results:
                    value = context.get_intermediate(source_var)
                elif source_var in (context.extra_params.get("runtime_params", {}) or {}):
                    value = context.extra_params.get("runtime_params", {}).get(source_var)
                elif source_var in (context.extra_params.get("base_payload", {}) or {}):
                    value = context.extra_params.get("base_payload", {}).get(source_var)
                elif bridge_var in context.intermediate_results:
                    value = context.get_intermediate(bridge_var)
                    if bridge_transform == "hex" and isinstance(value, str):
                        try:
                            value = base64.b64decode(value).hex()
                        except Exception:
                            pass
                elif field_source.get("derivation"):
                    value = self._evaluate_derivation(field_source.get("derivation"), context, current_output)
                if value is not None and source_expr.startswith("encodeURIComponent("):
                    from urllib.parse import quote_plus
                    value = quote_plus(str(value))
            elif source_name in value_derivations:
                value = self._evaluate_derivation(value_derivations[source_name], context, current_output)
            if value is not None:
                resolved_fields[field_name] = value

        if packing_type == "json":
            return json.dumps(resolved_fields, separators=(",", ":"), ensure_ascii=False)
        if packing_type == "url_search_params":
            from urllib.parse import urlencode
            return urlencode(resolved_fields)
        if packing_type == "template":
            rendered = packing_info.get("template", "")
            insertions = packing_info.get("insertions", []) or []
            for insertion in insertions:
                variable = insertion.get("variable")
                source_meta = field_sources.get(variable, {}) if isinstance(field_sources, dict) else {}
                source_var = source_meta.get("source_name", variable)
                value = None
                if source_var in context.intermediate_results:
                    value = context.get_intermediate(source_var)
                elif source_var in (context.extra_params.get("runtime_params", {}) or {}):
                    value = context.extra_params.get("runtime_params", {}).get(source_var)
                elif source_var in (context.extra_params.get("base_payload", {}) or {}):
                    value = context.extra_params.get("base_payload", {}).get(source_var)
                elif source_meta.get("derivation"):
                    value = self._evaluate_derivation(source_meta.get("derivation"), context, current_output)
                if value is None:
                    continue
                if str(source_meta.get("source_expression", "")).startswith("encodeURIComponent("):
                    from urllib.parse import quote_plus
                    value = quote_plus(str(value))
                rendered = rendered.replace(f"{{{{{variable}}}}}", str(value))
            return rendered
        return current_output

    def _coerce_bytes(self, value: Any) -> bytes:
        if value is None:
            return b""
        if isinstance(value, bytes):
            return value
        if isinstance(value, str):
            return value.encode("utf-8")
        return str(value).encode("utf-8")

#!/usr/bin/env python3
"""
Handler Pipeline
================
基于基线骨架 (Baseline Skeleton) 驱动的加密流水线执行器
"""

import base64
import json
import os
import random
from pathlib import Path
from typing import Dict, Any, List, Optional

from .base import CryptoContext, HandlerResult
from .registry import get_registry
from .validator import ValidationLayer  # Import ValidationLayer

class BaselinePipelineRunner:
    """
    基线驱动的流水线运行器

    解析 baseline_skeletons.json 中的 execution_flow，动态构建每个 API 的处理流水线。
    支持从文件加载多个骨架并批量执行验证。
    """

    def __init__(self, source: Any):
        """
        初始化运行器
        :param source: 可以是文件路径 (str/Path)、单个骨架字典 (dict) 或骨架列表 (list)
        """
        self.skeletons = []
        self.file_path = None
        self.registry = get_registry()

        if isinstance(source, (str, Path)):
            self.file_path = Path(source)
            if self.file_path.exists():
                with open(self.file_path, "r", encoding="utf-8") as f:
                    content = json.load(f)
                    if isinstance(content, list):
                        self.skeletons = content
                    elif isinstance(content, dict):
                        self.skeletons = [content]
        elif isinstance(source, list):
            self.skeletons = source
        elif isinstance(source, dict):
            self.skeletons = [source]

    def process_all(self, interactive: bool = False):
        """
        处理所有加载的基线骨架
        :param interactive: 是否启用交互式 Payload 输入
        """
        updated = False
        print(f"[*] Loaded {len(self.skeletons)} baseline entries.")

        for i, skeleton in enumerate(self.skeletons):
            meta = skeleton.get("meta", {})
            req = skeleton.get("request", {})
            val = skeleton.get("validation", {})
            runtime_params = val.get("runtime_params", {})
            endpoint_id = meta.get("id", f"entry_{i}")
            url = meta.get("url", "unknown")
            execution_flow = meta.get("execution_flow", [])

            print(f"\n>>> Processing Endpoint: {endpoint_id} ({url})")

            # 1. Check Payload
            payload = req.get("payload")
            if self._is_payload_missing(payload, runtime_params, execution_flow):
                print(f"[-] Payload missing or incomplete.")
                skeleton["status"] = "PENDING_PAYLOAD"
                if interactive:
                    hints = meta.get("hints", [])
                    print(f"    Hints: {hints}")
                    new_payload = self._prompt_payload()
                    if new_payload:
                        req["payload"] = new_payload
                        payload = new_payload
                        updated = True
                    else:
                        print("[-] Skipped.")
                        continue
                else:
                    print("[-] Skipped (Interactive mode disabled).")
                    continue

            # 2. Build Pipeline Steps & Context
            steps, flow_context = self._build_steps_and_context(execution_flow)

            # 3. Execution
            print("[*] Executing local handler...")

            # Merge context: global defaults + flow extracted (keys/ivs) + payload
            pipeline_context = {
                "endpoint_id": endpoint_id,
                "url": url,
                "base_payload": payload
            }
            pipeline_context.update(flow_context)

            pipeline_config = {
                "steps": steps,
                "context": pipeline_context
            }
            pipeline = HandlerPipeline(pipeline_config)

            # Inject capture runtime parameters (Keys, IVs, Nonces) to ensure deterministic reproduction
            if runtime_params:
                print(f"[*] Injecting runtime params: {list(runtime_params.keys())}")
                # Ensure we don't overwrite payload if it's there, though payload is 1st arg

            # 使用基线 payload 作为唯一输入来源，避免验证阶段的启发式兜底。
            input_data = payload

            result = pipeline.execute(input_data, **runtime_params)

            if result.success:
                verification_output = self._select_verification_output(result, execution_flow)
                print(f"[+] Success. Output prefix: {str(verification_output)[:50]}...")
                val["handler_ciphertext"] = verification_output
                val["last_run"] = "success"
                val.pop("errors", None)
                skeleton["status"] = "HANDLER_EXECUTED"
                updated = True
            else:
                print(f"[-] Failed: {result.error}")
                val["last_run"] = "failed"
                val["errors"] = [result.error]
                skeleton["status"] = "HANDLER_FAILED"
                updated = True

            # 4. Verification (if captured ciphertext exists)
            captured = val.get("captured_ciphertext")

            # Check for non-crypto endpoints (PayloadPacking only)
            algos = meta.get("crypto_algorithms", [])
            is_encryption = any(algo not in ["PayloadPacking"] for algo in algos)

            if not is_encryption:
                print(f"[+] INFO: Endpoint performs Payload Packing only (No client-side crypto).")
                print(f"    Marking as VERIFIED.")
                val["verified"] = True
                val["comparison_result"] = "NO_CRYPTO"
                skeleton["status"] = "VERIFIED"
            elif captured:
                # Use ValidationLayer for robust comparison
                # We use self.file_path if available, otherwise fallback to empty path which ValidationLayer handles if it doesn't exist?
                # Actually ValidationLayer requires a path. self.file_path is usually set.
                validator_path = self.file_path if self.file_path else Path("dummy_non_existent.json")
                validator = ValidationLayer(validator_path)

                # Mock result for validation
                val_result = validator.validate_simple(captured, verification_output)

                # Check RSA/AESRSA context for relaxed validation
                algos = meta.get("crypto_algorithms", [])
                algos_str = [str(a).upper() for a in algos]
                is_rsa = "RSA" in algos_str or "AESRSA" in algos_str

                if val_result.matched:
                    print(f"[+] VERIFIED: Matches captured ciphertext ({val_result.matched_strategy}).")
                    val["verified"] = True
                    val["comparison_result"] = "MATCH"
                    skeleton["status"] = "VERIFIED"
                else:
                    if is_rsa:
                        print(f"[*] RSA Detected: Skipping strict ciphertext comparison (Random Padding).")
                        print(f"    Marking as VERIFIED (Logic Validated).")
                        val["verified"] = True
                        val["comparison_result"] = "RSA_NONDETERMINISTIC_LOGIC_VALIDATED"
                        skeleton["status"] = "VERIFIED"
                    else:
                        print(f"[-] MISMATCH: Does not match captured ciphertext.")
                        # print(f"    Expected: {captured}")
                        # print(f"    Actual:   {result.output}")
                        val["verified"] = False
                        val["comparison_result"] = "MISMATCH"
                        skeleton["status"] = "VERIFICATION_FAILED"
            else:
                if result.success:
                    skeleton["status"] = "READY"

        if updated and self.file_path:
            self._save()

    def _select_verification_output(self, result: HandlerResult, execution_flow: List[Dict]) -> Any:
        if not result or not result.success or not result.context:
            return result.output if result else None

        for step_info in reversed(execution_flow):
            step_type = str(step_info.get("step_type", "")).lower()
            if step_type not in ["encrypt", "sign"]:
                continue
            output_variable = step_info.get("output_variable")
            if output_variable:
                candidate = result.context.get_intermediate(output_variable)
                if candidate is not None:
                    return candidate
        return result.output

    def _save(self):
        with open(self.file_path, "w", encoding="utf-8") as f:
            json.dump(self.skeletons, f, indent=2, ensure_ascii=False)
        print(f"\n[+] Updated baseline file: {self.file_path}")

    def _is_payload_missing(
        self,
        payload: Any,
        runtime_params: Optional[Dict[str, Any]] = None,
        execution_flow: Optional[List[Dict[str, Any]]] = None,
    ) -> bool:
        if not payload:
            return True

        # 这些字段通常由运行时（hook 或 handler）回填，不要求用户在 payload 中手工填写
        runtime_fillable_fields = {
            "signature", "timestamp", "nonce", "random", "encryptedTimestamp"
        }
        runtime_params = runtime_params or {}

        # 由 execution_flow 自动生成/回填的字段：不要求用户手工填写。
        flow_fillable_fields = set(runtime_fillable_fields)
        for step in execution_flow or []:
            output_var = step.get("output_variable")
            if output_var:
                flow_fillable_fields.add(str(output_var))

            if str(step.get("step_type", "")).lower() == "pack":
                packing_info = (step.get("runtime_args", {}) or {}).get("packing_info", {}) or {}
                structure = packing_info.get("structure", {}) or {}
                for source_name in structure.values():
                    if source_name:
                        flow_fillable_fields.add(str(source_name))
                field_sources = packing_info.get("field_sources", {}) or {}
                if isinstance(field_sources, dict):
                    for _, source_meta in field_sources.items():
                        if isinstance(source_meta, dict) and source_meta.get("source_name"):
                            flow_fillable_fields.add(str(source_meta.get("source_name")))

        if isinstance(payload, dict):
            if "_comment" in payload:
                return True

            # 若字段是可运行时回填字段，且 runtime_params 中已有对应值，则不视为缺失
            for key, value in payload.items():
                if value != "<Fill Value>":
                    continue
                if key in flow_fillable_fields:
                    continue
                if key in runtime_fillable_fields and runtime_params.get(key) not in [None, "", "<Fill Value>"]:
                    continue
                return True

        return False

    def _prompt_payload(self) -> Optional[Dict]:
        print("Please enter valid JSON payload (or 's' to skip):")
        try:
            raw = input("JSON > ").strip()
            if raw.lower() == 's': return None
            return json.loads(raw)
        except Exception as e:
            print(f"[!] Invalid input: {e}")
            return None

    def _build_steps_and_context(self, execution_flow: List[Dict]):
        """
        根据 execution_flow 构建可执行的 steps 和 context params
        Returns: (steps, context_params)
        """
        steps = []
        context_params = {}

        # 遍历 execution_flow 中的原子操作
        for step_info in execution_flow:
            step_type = step_info.get("step_type", "").lower() # e.g., init, setkey, encrypt
            algorithm = step_info.get("algorithm", "")
            runtime_args = step_info.get("runtime_args", {})

            # 1. Context Setters: init, setkey, setiv, hardcoded_secret
            if step_type in ["init", "setkey", "setiv", "hardcoded_secret"]:
                if runtime_args:
                    context_params.update(runtime_args)
                continue

            # NEW: Variable Derivation (Key/IV)
            elif step_type.startswith("derive_"):
                # runtime_args contains "derivation"
                target = step_type.replace("derive_", "") # key or iv
                steps.append({
                    "operation": "variable_derivation",
                    "algorithm": "Derivation",
                    "params": {
                        "target": target,
                        "derivation": runtime_args.get("derivation")
                    }
                })
                continue

            # 2. Encrypt/Sign/Pack操作
            elif step_type in ["encrypt", "sign", "pack"]:
                # 特殊处理 pack：保留 packing_info，让流水线也能尝试组装请求体
                if step_type == "pack":
                     steps.append({
                         "operation": "payload_pack",
                         "algorithm": "PayloadPacking",
                         "params": runtime_args,
                         "packing_info": runtime_args.get("packing_info", {}),
                         "source_context": step_info.get("context", "")
                     })
                     continue

                operation_name = self._map_operation(algorithm, step_type)
                if operation_name:
                    step_config = {
                        "operation": operation_name,
                        "algorithm": algorithm,
                        "params": runtime_args
                    }
                    if step_info.get("output_variable"):
                        step_config["output_variable"] = step_info.get("output_variable")
                    if step_info.get("context"):
                        step_config["source_context"] = step_info.get("context")
                    if step_info.get("input_expression"):
                        step_config["input_expression"] = step_info.get("input_expression")
                    if step_info.get("input_derivation"):
                        step_config["input_derivation"] = step_info.get("input_derivation")
                    if step_info.get("input_source_keys"):
                        step_config["input_source_keys"] = step_info.get("input_source_keys")
                    if step_info.get("output_transform"):
                        step_config["output_transform"] = step_info.get("output_transform")
                    steps.append(step_config)

            # 3. 其他操作
            else:
                pass

        return steps, context_params

    def _build_steps(self, execution_flow: List[Dict]) -> List[Dict[str, Any]]:
        steps, _ = self._build_steps_and_context(execution_flow)
        return steps


    def _map_operation(self, algorithm: str, op_type: str) -> Optional[str]:
        """将算法+操作映射为 registry 中的 operation_name"""
        algo = algorithm.upper()
        op = op_type.lower()

        mapping = {
            "AES": {"encrypt": "aes_encrypt", "decrypt": "aes_decrypt"},
            "DES": {"encrypt": "des_encrypt", "decrypt": "des_decrypt"},
            "RSA": {"encrypt": "rsa_encrypt", "decrypt": "rsa_decrypt"},
            "HMACSHA256": {"sign": "hmac_sha256"},
            "HMACSHA256()": {"sign": "hmac_sha256"},
            "MD5": {"sign": "md5", "encrypt": "md5"}, # MD5通常叫hash，但也可能被标记为sign
            "SHA256": {"sign": "sha256", "encrypt": "sha256"},
            # 默认回退
            "UNKNOWN": {}
        }

        if algo in mapping and op in mapping[algo]:
            return mapping[algo][op]

        # 尝试通用命名
        potential_name = f"{algo.lower()}_{op}"
        if self.registry.get_operation(potential_name):
            return potential_name

        return None



class HandlerPipeline:
    """
    加密流水线 (Handler Pipeline)

    不再依赖独立的 YAML 配置文件，而是直接通过字典配置（来自基线 JSON 的 meta 信息）初始化。
    负责按顺序执行一系列加密或解密操作。
    """

    def __init__(self, config: Dict[str, Any]):
        """
        初始化流水线

        Args:
            config: 流水线配置字典
                {
                    "steps": [ ... ],       # 操作步骤列表
                    "context": { ... }      # 初始上下文 (endpoint_id, url 等)
                }
        """
        self.config = config
        self.registry = get_registry()
        self.steps = config.get("steps", [])
        self.global_context = config.get("context", {})

    def execute(self, input_data: Any, **extra_params) -> HandlerResult:
        """
        执行流水线

        Args:
            input_data: 初始输入数据（通常是 request.payload）
            **extra_params: 运行时注入的额外参数（如从 Hook 捕获的 Key/IV）

        Returns:
            HandlerResult: 包含最终结果和执行上下文
        """
        # 1. 初始化执行上下文
        context = self._build_context(input_data, extra_params)

        # 2. 依次执行每个步骤
        current_output = input_data
        context.logs.append(f"开始执行流水线，共 {len(self.steps)} 个步骤")

        for i, step in enumerate(self.steps):
            # 获取操作名称
            # 优先使用显式指定的 'operation'
            operation_name = step.get("operation")

            # 兼容旧逻辑：如果未指定 operation，尝试根据 algorithm + type 推断
            if not operation_name and "algorithm" in step:
                algo = step.get("algorithm", "").lower()
                # 默认为 encrypt，除非显式覆盖
                op_type = step.get("operation_type", "encrypt").lower()

                # 特殊处理：如果 step 有 "operation" 字段但不是标准名称（如 static analysis 中的 "encrypt"）
                if "operation" in step and step["operation"] in ["encrypt", "decrypt", "sign", "verify"]:
                     op_type = step["operation"].lower()

                operation_name = f"{algo}_{op_type}"

            if not operation_name:
                return HandlerResult(
                    success=False,
                    error=f"步骤 {i}: 缺少操作名称 (operation)",
                    context=context
                )

            # 3. 参数注入与上下文更新
            # 将步骤配置中的 params 合并入 context
            step_params = step.get("params", {})
            for key, value in step_params.items():
                if hasattr(context, key):
                   setattr(context, key, value)
                else:
                   context.extra_params[key] = value

            if operation_name == "payload_pack":
                try:
                    packed_output = self._build_packed_output(step, context, current_output)
                    current_output = packed_output
                    output_variable = step.get("output_variable")
                    if output_variable:
                        context.set_intermediate(output_variable, packed_output)
                    context.logs.append(f"步骤 {i} (payload_pack) 完成")
                    continue
                except Exception as e:
                    return HandlerResult(
                        success=False,
                        error=f"步骤 {i} (payload_pack) 执行异常: {str(e)}",
                        context=context
                    )

            # 获取操作类实例
            operation_class = self.registry.get_operation(operation_name)
            if not operation_class:
                return HandlerResult(
                    success=False,
                    error=f"步骤 {i}: 未知的操作 '{operation_name}'",
                    context=context
                )

            # 将步骤配置中的 details (来自静态分析) 尝试合入 context
            if "details" in step and isinstance(step["details"], list):
                 for detail_item in step["details"]:
                     if isinstance(detail_item, dict):
                         for k, v in detail_item.items():
                             if k not in ["operation", "line", "context"] and hasattr(context, k):
                                 setattr(context, k, v)

            # 设置当前步骤的输入数据
            resolved_input = self._resolve_step_input(step, context, current_output)
            context.plaintext = resolved_input

            # 4. 执行具体操作
            try:
                operation = operation_class()
                result = operation.execute(context)
            except Exception as e:
                return HandlerResult(
                    success=False,
                    error=f"步骤 {i} ({operation_name}) 执行异常: {str(e)}",
                    context=context
                )

            if not result.success:
                return HandlerResult(
                    success=False,
                    error=f"步骤 {i} ({operation_name}) 失败: {result.error}",
                    context=context
                )

            output_value = result.output
            if step.get("output_transform"):
                output_value = self._apply_output_transform(step.get("output_transform"), output_value, context)

            # 更新中间结果，准备下一步
            context.set_intermediate(f"step_{i}_output", output_value)
            output_variable = step.get("output_variable")
            if output_variable:
                context.set_intermediate(output_variable, output_value)
            current_output = output_value
            context.logs.append(f"步骤 {i} ({operation_name}) 完成")

        # 返回最终结果
        return HandlerResult(
            success=True,
            output=current_output,
            context=context,
            metadata={"steps_executed": len(self.steps)}
        )

    def _build_context(self, input_data: Any, extra_params: Dict) -> CryptoContext:
        """构建初始执行上下文"""
        context_params = {**self.global_context, **extra_params}
        context = CryptoContext(plaintext=input_data)

        for key, value in context_params.items():
            if hasattr(context, key):
                setattr(context, key, value)
            else:
                context.extra_params[key] = value

        context.extra_params.setdefault("runtime_params", dict(extra_params))
        return context

    def _resolve_step_input(self, step: Dict[str, Any], context: CryptoContext, current_output: Any) -> Any:
        input_expression = step.get("input_expression")
        input_derivation = step.get("input_derivation")
        input_source_keys = step.get("input_source_keys") or []
        base_payload = context.extra_params.get("base_payload", {}) or {}

        if input_expression:
            resolved = self._resolve_expression(input_expression, context, current_output)
            if resolved is not None:
                if (
                    isinstance(resolved, str)
                    and str(input_expression).strip().startswith("JSON.stringify(")
                    and isinstance(base_payload, dict)
                    and input_source_keys
                ):
                    ordered_json = self._stringify_with_preferred_order(base_payload, input_source_keys)
                    if ordered_json is not None:
                        return ordered_json
                return resolved

        if input_derivation:
            resolved = self._evaluate_derivation(input_derivation, context, current_output)
            if resolved is not None:
                return resolved

        return current_output

    def _stringify_with_preferred_order(self, payload: Dict[str, Any], preferred_keys: List[Any]) -> Optional[str]:
        if not isinstance(payload, dict):
            return None
        ordered: Dict[str, Any] = {}
        seen: set[str] = set()
        for key in preferred_keys:
            key_text = str(key)
            if key_text in payload and key_text not in seen:
                ordered[key_text] = payload[key_text]
                seen.add(key_text)
        for key, value in payload.items():
            if key not in seen:
                ordered[key] = value
        return json.dumps(ordered, separators=(",", ":"), ensure_ascii=False)

    def _resolve_expression(self, expression: str, context: CryptoContext, current_output: Any) -> Any:
        expr = str(expression).strip()
        if not expr:
            return None

        if expr in context.intermediate_results:
            return context.get_intermediate(expr)

        runtime_params = context.extra_params.get("runtime_params", {}) or {}
        base_payload = context.extra_params.get("base_payload", {}) or {}

        if expr in base_payload:
            return base_payload[expr]
        if expr in runtime_params:
            return runtime_params[expr]
        if expr in ["jsonData", "dataString", "formData", "dataToSend", "dataPacket"]:
            return json.dumps(base_payload, separators=(",", ":"), ensure_ascii=False)
        if expr.startswith("JSON.stringify(") and expr.endswith(")"):
            inner = expr[len("JSON.stringify("):-1].strip()
            inner_val = self._resolve_expression(inner, context, current_output)
            if inner_val is None:
                return None
            if isinstance(inner_val, str):
                return inner_val
            return json.dumps(inner_val, separators=(",", ":"), ensure_ascii=False)
        if expr.endswith(".toString(CryptoJS.enc.Base64)"):
            base_name = expr.split(".", 1)[0]
            base_val = self._resolve_expression(base_name, context, current_output)
            if base_val is None:
                return None
            return base64.b64encode(self._coerce_bytes(base_val)).decode("ascii")
        if expr.endswith(".toString()"):
            base_name = expr.split(".", 1)[0]
            base_val = self._resolve_expression(base_name, context, current_output)
            if base_val is None:
                return None
            return str(base_val)
        if expr in ["key", "iv", "publicKey"]:
            lookup = {
                "key": context.key,
                "iv": context.iv,
                "publicKey": context.extra_params.get("public_key") or context.key
            }
            return lookup.get(expr)

        return None

    def _evaluate_derivation(self, node: Any, context: CryptoContext, current_output: Any) -> Any:
        if not isinstance(node, dict):
            return node

        node_type = node.get("type")
        runtime_params = context.extra_params.get("runtime_params", {}) or {}
        base_payload = context.extra_params.get("base_payload", {}) or {}

        if node_type == "source":
            key_name = node.get("value")
            if key_name in base_payload:
                return base_payload.get(key_name)
            return runtime_params.get(key_name)

        if node_type == "literal":
            return node.get("value")

        if node_type == "identifier":
            name = node.get("name")
            if name in context.intermediate_results:
                return context.get_intermediate(name)
            if name in base_payload:
                return base_payload.get(name)
            if name in runtime_params:
                return runtime_params.get(name)
            if name == "timestamp":
                return runtime_params.get("timestamp") or int(__import__("time").time())
            return None

        if node_type == "member_access":
            source_val = self._evaluate_derivation(node.get("input"), context, current_output)
            prop = node.get("property")
            if prop == "ciphertext":
                return source_val
            if isinstance(source_val, dict):
                return source_val.get(prop)
            return None

        if node_type == "binary_op":
            left = self._evaluate_derivation(node.get("left"), context, current_output)
            right = self._evaluate_derivation(node.get("right"), context, current_output)
            if node.get("op") == "+":
                return f"{'' if left is None else left}{'' if right is None else right}"
            return None

        if node_type == "call":
            callee = node.get("callee")
            args = [self._evaluate_derivation(arg, context, current_output) for arg in node.get("args", [])]
            expression = node.get("expression", "")
            if callee == "Math.random":
                if runtime_params.get("nonce"):
                    return f"0.{runtime_params.get('nonce')}"
                return random.random()
            if callee == "Math.floor":
                if "Date.now() / 1000" in expression:
                    return runtime_params.get("timestamp") or int(__import__("time").time())
                return int(args[0]) if args and isinstance(args[0], (int, float)) else None
            if callee == "Date.now":
                return runtime_params.get("timestamp") or int(__import__("time").time() * 1000)
            if callee == "CryptoJS.lib.WordArray.random":
                length = int(args[0]) if args else 16
                return os.urandom(length)
            return runtime_params.get(callee) or None

        if node_type == "op":
            input_val = self._evaluate_derivation(node.get("input"), context, current_output)
            args = [self._evaluate_derivation(arg, context, current_output) for arg in node.get("args", [])]
            op_name = node.get("op")

            if op_name == "JSON.stringify":
                if isinstance(input_val, str):
                    return input_val
                return json.dumps(input_val, separators=(",", ":"), ensure_ascii=False)
            if op_name == "toString":
                codec = args[0] if args else None
                if codec == "CryptoJS.enc.Base64":
                    return base64.b64encode(self._coerce_bytes(input_val)).decode("ascii")
                if codec == "CryptoJS.enc.Hex":
                    return self._coerce_bytes(input_val).hex()
                if isinstance(input_val, str) and args and args[0] == 36:
                    return input_val
                if isinstance(input_val, float) and args and args[0] == 36:
                    return str(input_val)
                return str(input_val)
            if op_name == "substring":
                start = int(args[0]) if len(args) > 0 and args[0] is not None else 0
                end = int(args[1]) if len(args) > 1 and args[1] is not None else None
                return str(input_val)[start:end]
            if op_name == "slice":
                start = int(args[0]) if len(args) > 0 and args[0] is not None else 0
                end = int(args[1]) if len(args) > 1 and args[1] is not None else None
                return str(input_val)[start:end]
            if op_name == "padEnd":
                width = int(args[0]) if len(args) > 0 and args[0] is not None else len(str(input_val))
                fillchar = str(args[1]) if len(args) > 1 and args[1] is not None else " "
                text = str(input_val)
                if len(text) >= width:
                    return text
                return text + (fillchar * (width - len(text)))[: width - len(text)]
            if op_name in ["Utf8.parse", "Hex.parse", "Base64.parse"]:
                return self._coerce_bytes(input_val)

        return None

    def _apply_output_transform(self, transform: str, output_value: Any, context: CryptoContext) -> Any:
        transform = str(transform)
        if ".toString(CryptoJS.enc.Hex)" in transform:
            if isinstance(output_value, str):
                candidate = output_value.strip().lower()
                if candidate and all(ch in "0123456789abcdef" for ch in candidate):
                    return output_value
            return self._coerce_bytes(output_value).hex()
        if ".toString(CryptoJS.enc.Base64)" in transform:
            if isinstance(output_value, str):
                return output_value
            return base64.b64encode(self._coerce_bytes(output_value)).decode("ascii")
        return output_value

    def _build_packed_output(self, step: Dict[str, Any], context: CryptoContext, current_output: Any) -> Any:
        packing_info = step.get("packing_info") or step.get("params", {}).get("packing_info") or {}
        packing_type = packing_info.get("type")
        structure = packing_info.get("structure", {}) or {}
        field_sources = packing_info.get("field_sources", {}) or {}
        value_derivations = packing_info.get("value_derivations", {}) or {}

        resolved_fields = {}
        for field_name, source_name in structure.items():
            value = None
            if source_name in context.intermediate_results:
                value = context.get_intermediate(source_name)
            elif source_name in (context.extra_params.get("runtime_params", {}) or {}):
                value = context.extra_params.get("runtime_params", {}).get(source_name)
            elif source_name in (context.extra_params.get("base_payload", {}) or {}):
                value = context.extra_params.get("base_payload", {}).get(source_name)
            elif field_name in field_sources and isinstance(field_sources[field_name], dict):
                field_source = field_sources[field_name]
                source_expr = str(field_source.get("source_expression", ""))
                source_var = field_source.get("source_name")
                bridge_var = field_source.get("bridge_from_output")
                bridge_transform = str(field_source.get("bridge_transform", "")).lower()
                if source_var in context.intermediate_results:
                    value = context.get_intermediate(source_var)
                elif source_var in (context.extra_params.get("runtime_params", {}) or {}):
                    value = context.extra_params.get("runtime_params", {}).get(source_var)
                elif source_var in (context.extra_params.get("base_payload", {}) or {}):
                    value = context.extra_params.get("base_payload", {}).get(source_var)
                elif bridge_var in context.intermediate_results:
                    value = context.get_intermediate(bridge_var)
                    if bridge_transform == "hex" and isinstance(value, str):
                        try:
                            value = base64.b64decode(value).hex()
                        except Exception:
                            pass
                elif field_source.get("derivation"):
                    value = self._evaluate_derivation(field_source.get("derivation"), context, current_output)
                if value is not None and source_expr.startswith("encodeURIComponent("):
                    from urllib.parse import quote_plus
                    value = quote_plus(str(value))
            elif source_name in value_derivations:
                value = self._evaluate_derivation(value_derivations[source_name], context, current_output)
            if value is not None:
                resolved_fields[field_name] = value

        if packing_type == "json":
            return json.dumps(resolved_fields, separators=(",", ":"), ensure_ascii=False)
        if packing_type == "url_search_params":
            from urllib.parse import urlencode
            return urlencode(resolved_fields)
        if packing_type == "template":
            rendered = packing_info.get("template", "")
            insertions = packing_info.get("insertions", []) or []
            for insertion in insertions:
                variable = insertion.get("variable")
                source_meta = field_sources.get(variable, {}) if isinstance(field_sources, dict) else {}
                source_var = source_meta.get("source_name", variable)
                value = None
                if source_var in context.intermediate_results:
                    value = context.get_intermediate(source_var)
                elif source_var in (context.extra_params.get("runtime_params", {}) or {}):
                    value = context.extra_params.get("runtime_params", {}).get(source_var)
                elif source_var in (context.extra_params.get("base_payload", {}) or {}):
                    value = context.extra_params.get("base_payload", {}).get(source_var)
                elif source_meta.get("derivation"):
                    value = self._evaluate_derivation(source_meta.get("derivation"), context, current_output)
                if value is None:
                    continue
                if str(source_meta.get("source_expression", "")).startswith("encodeURIComponent("):
                    from urllib.parse import quote_plus
                    value = quote_plus(str(value))
                rendered = rendered.replace(f"{{{{{variable}}}}}", str(value))
            return rendered
        return current_output

    def _coerce_bytes(self, value: Any) -> bytes:
        if value is None:
            return b""
        if isinstance(value, bytes):
            return value
        if isinstance(value, str):
            return value.encode("utf-8")
        return str(value).encode("utf-8")

#!/usr/bin/env python3
"""Layer1 自动化生成：按算法条件组合生成基础稳定池。"""

from __future__ import annotations

import argparse
import itertools
import sys
from pathlib import Path
from typing import Any

BASE_DIR = Path(__file__).resolve().parents[2]
sys.path.insert(0, str(BASE_DIR))

from scripts.api_lab_builder.common import PruneRecord, append_jsonl, dedupe_key, dump_json, dump_yaml, load_yaml


def _product_dict(matrix: dict[str, list[Any]]) -> list[dict[str, Any]]:
    keys = list(matrix.keys())
    rows = []
    for values in itertools.product(*(matrix[k] for k in keys)):
        rows.append({k: v for k, v in zip(keys, values)})
    return rows


def _make_spec(algorithm: str, base: dict[str, Any], fixed: dict[str, Any], row: dict[str, Any]) -> dict[str, Any]:
    spec: dict[str, Any] = {
        "algorithm_stack": algorithm,
        "algo_params": {},
        "material_source": base.get("material_source"),
        "material_dynamicity": dict(base.get("material_dynamicity", {})),
        "validation_hops": fixed.get("validation_hops", "single_hop"),
        "anti_replay": row.get("anti_replay", "none"),
        "interlayers": list(fixed.get("interlayers", [])),
        "risk_tags": list(base.get("risk_tags", [])),
        "template_level": base.get("template_level", "BASELINE"),
    }

    if "session_policy" in base:
        spec["session_policy"] = dict(base["session_policy"])

    if algorithm == "PLAINTEXT_HMAC":
        placement = row.get("signature_placement") or base.get("signature_strategy", {}).get("placement")
        spec["signature_strategy"] = {"placement": placement}

    for key, value in row.items():
        if key in {"anti_replay", "signature_placement"}:
            continue
        spec["algo_params"][key] = value

    return spec


def _materialize_layer1_item(spec: dict[str, Any], cfg: dict[str, Any], seq: int) -> dict[str, Any]:
    item = dict(spec)
    item["algo_params"] = dict(spec.get("algo_params", {}))
    item["material_dynamicity"] = dict(spec.get("material_dynamicity", {}))
    item["risk_tags"] = list(spec.get("risk_tags", []))
    item["interlayers"] = list(spec.get("interlayers", []))
    if "signature_strategy" in spec:
        item["signature_strategy"] = dict(spec.get("signature_strategy", {}))
    if "session_policy" in spec:
        item["session_policy"] = dict(spec.get("session_policy", {}))

    # Layer1 不展开 2.7 路由维度，固定为基础路由，Layer5 再做翻倍展开。
    item["route_variant"] = "PLAIN_ROUTE"
    item["site_group"] = cfg["global"]["fixed_site_group"]
    item["id"] = f"layer1_{seq:05d}"
    return item


def _check_conflicts(spec: dict[str, Any], cfg: dict[str, Any]) -> list[PruneRecord]:
    errors: list[PruneRecord] = []
    spec_id = str(spec.get("id", "<unknown>"))
    algo = str(spec.get("algorithm_stack", ""))
    params = spec.get("algo_params", {}) if isinstance(spec.get("algo_params"), dict) else {}
    dynamic = spec.get("material_dynamicity", {}) if isinstance(spec.get("material_dynamicity"), dict) else {}
    anti_replay = str(spec.get("anti_replay", ""))
    signature_strategy = spec.get("signature_strategy", {}) if isinstance(spec.get("signature_strategy"), dict) else {}
    session_policy = spec.get("session_policy", {}) if isinstance(spec.get("session_policy"), dict) else {}

    # 兼容“原语链命名 + 历史命名”
    is_aes = algo in {"AES", "AES_CBC"}
    is_des = algo in {"DES", "DES_CBC"}
    is_rsa_only = algo == "RSA_ONLY"
    is_plain_hmac = algo == "PLAINTEXT_HMAC"

    # 字段唯一归属：algo_params 只能承载算法参数
    forbidden_param_keys = {
        "anti_replay",
        "material_source",
        "material_dynamicity",
        "signature_strategy",
        "session_policy",
        "signature_placement",
    }
    touched_forbidden = sorted(k for k in params.keys() if k in forbidden_param_keys)
    if touched_forbidden:
        errors.append(
            PruneRecord(
                spec_id,
                "CONFLICT_FIELD_OWNERSHIP_ALGO_PARAMS",
                f"algo_params 出现越权字段: {','.join(touched_forbidden)}",
            )
        )

    # signature_strategy 仅允许 coverage/placement
    invalid_sig_keys = sorted(k for k in signature_strategy.keys() if k not in {"coverage", "placement"})
    if invalid_sig_keys:
        errors.append(
            PruneRecord(
                spec_id,
                "CONFLICT_FIELD_OWNERSHIP_SIGNATURE_STRATEGY",
                f"signature_strategy 非法字段: {','.join(invalid_sig_keys)}",
            )
        )

    if algo not in set(cfg["global"]["algorithm_whitelist"]):
        errors.append(PruneRecord(spec_id, "SCHEMA_ALGO_NOT_ALLOWED", f"算法不在白名单: {algo}"))

    if str(spec.get("route_variant", "")) not in set(cfg["global"]["allowed_route_variants"]):
        errors.append(PruneRecord(spec_id, "SCHEMA_ROUTE_NOT_ALLOWED", "route_variant 不在允许集合"))

    if (is_aes or is_des) and str(params.get("mode", "")) == "":
        errors.append(PruneRecord(spec_id, "CONFLICT_SYMMETRIC_MODE_MISSING", "AES/DES 必须声明 mode"))

    if is_aes or is_des:
        mode = str(params.get("mode", "")).upper()
        if mode in {"CBC", "CFB", "OFB", "CTR"} and str(params.get("iv_policy", "absent")) == "absent":
            errors.append(
                PruneRecord(spec_id, "CONFLICT_SYMMETRIC_IV_ABSENT", "对称算法在该 mode 下要求 iv_policy != absent")
            )

    if is_rsa_only:
        blocked = [k for k in ["mode", "iv_policy", "padding"] if k in params]
        if blocked:
            errors.append(PruneRecord(spec_id, "CONFLICT_RSA_ONLY_SYMMETRIC_PARAMS", f"RSA_ONLY 禁止参数: {','.join(blocked)}"))

    if is_plain_hmac:
        blocked = [k for k in ["key_size", "mode", "iv_policy", "padding"] if k in params]
        if blocked:
            errors.append(
                PruneRecord(spec_id, "CONFLICT_HMAC_SYMMETRIC_PARAMS", f"PLAINTEXT_HMAC 禁止参数: {','.join(blocked)}")
            )

        placement = str(signature_strategy.get("placement", ""))
        if placement not in {"body", "header", "query"}:
            errors.append(PruneRecord(spec_id, "CONFLICT_HMAC_NO_PLACEMENT", "HMAC 需要签名放置位置"))

    def _dyn_missing(name: str) -> bool:
        return str(dynamic.get(name, "absent")) == "absent"

    if anti_replay == "timestamp_only" and _dyn_missing("timestamp"):
        errors.append(PruneRecord(spec_id, "CONFLICT_ANTI_REPLAY_TIMESTAMP_MISSING", "timestamp_only 缺少 timestamp"))

    if anti_replay == "nonce_only" and _dyn_missing("nonce"):
        errors.append(PruneRecord(spec_id, "CONFLICT_ANTI_REPLAY_NONCE_MISSING", "nonce_only 缺少 nonce"))

    if anti_replay == "nonce_timestamp":
        missing = [k for k in ["nonce", "timestamp"] if _dyn_missing(k)]
        if missing:
            errors.append(PruneRecord(spec_id, "CONFLICT_ANTI_REPLAY_NONCE_TIMESTAMP_MISSING", f"依赖缺失: {','.join(missing)}"))

    if anti_replay in {"nonce_timestamp_signature", "nonce_timestamp_signature_session_binding"}:
        missing = [k for k in ["nonce", "timestamp", "signature"] if _dyn_missing(k)]
        placement = str(signature_strategy.get("placement", ""))
        if placement not in {"body", "header", "query"}:
            missing.append("signature_placement")
        if anti_replay == "nonce_timestamp_signature_session_binding" and str(session_policy.get("binding", "")) != "bind_cookie":
            missing.append("session_binding")
        if missing:
            errors.append(PruneRecord(spec_id, "CONFLICT_ANTI_REPLAY_INCOMPLETE", f"依赖缺失: {','.join(missing)}"))

    if str(params.get("padding", "")) == "NoPadding" and not bool(params.get("plaintext_block_aligned", False)):
        errors.append(PruneRecord(spec_id, "CONFLICT_NOPADDING_ALIGNMENT", "NoPadding 需要块对齐"))

    if len(spec.get("interlayers", [])) > int(cfg["constraints"]["max_interlayers"]):
        errors.append(PruneRecord(spec_id, "CONFLICT_INTERLAYERS_OVERFLOW", "夹层层数超过上限"))

    if set(str(tag).upper() for tag in spec.get("risk_tags", [])) & set(
        str(tag).upper() for tag in cfg["constraints"].get("unsupported_markers", [])
    ):
        errors.append(PruneRecord(spec_id, "UNSUPPORTED_COMPLEX_CUSTOM_CRYPTO", "命中不支持复杂样本标记"))

    return errors


def run_layer1_generate(config_path: Path, output_dir: Path | None = None) -> dict[str, Any]:
    cfg = load_yaml(config_path)
    out_cfg = cfg["output"]
    out_root = output_dir or (BASE_DIR / out_cfg["directory"])
    out_root.mkdir(parents=True, exist_ok=True)

    fixed = cfg["layer1"]["fixed"]
    # 兼容新旧命名：优先原语链（AES），兼容历史键（AES_CBC）
    order = ["AES", "AES_CBC", "RSA_ONLY", "PLAINTEXT_HMAC"]

    candidates: list[dict[str, Any]] = []
    seq = 1
    for algorithm in order:
        if algorithm not in cfg["layer1"]["algorithms"]:
            continue
        item = cfg["layer1"]["algorithms"][algorithm]
        base = item["base"]
        matrix = item["matrix"]
        for row in _product_dict(matrix):
            spec = _make_spec(algorithm, base, fixed, row)
            candidates.append(_materialize_layer1_item(spec, cfg, seq))
            seq += 1

    prune_records: list[PruneRecord] = []
    passed_conflict: list[dict[str, Any]] = []
    for spec in candidates:
        conflicts = _check_conflicts(spec, cfg)
        if conflicts:
            prune_records.extend(conflicts)
            continue
        passed_conflict.append(spec)

    selected: list[dict[str, Any]] = []
    seen: dict[str, str] = {}
    for spec in passed_conflict:
        key = dedupe_key(spec)
        spec["_dedupe_key"] = key
        if key in seen:
            prune_records.append(
                PruneRecord(spec["id"], "DUPLICATE_SPEC", f"与 {seen[key]} 去重键冲突")
            )
            continue
        seen[key] = spec["id"]
        selected.append(spec)

    reason_counts: dict[str, int] = {}
    for row in prune_records:
        reason_counts[row.reason_code] = reason_counts.get(row.reason_code, 0) + 1

    report = {
        "counts": {
            "generated_candidates": len(candidates),
            "after_conflict_prune": len(passed_conflict),
            "selected": len(selected),
            "pruned": len(prune_records),
        },
        "pruned_reason_counts": reason_counts,
        "gate": {
            "has_selected": len(selected) > 0,
        },
        "notes": {
            "layer": "Layer1",
            "model": "conditional_sum_product_then_prune",
            "execution_order": order,
        },
    }

    dump_yaml(out_root / out_cfg["layer1_pool_yaml"], selected)
    dump_json(out_root / out_cfg["layer1_pool_json"], selected)
    dump_json(out_root / out_cfg["layer1_gate_report"], report)
    append_jsonl(
        out_root / out_cfg["layer1_pruned_reasons"],
        [{"spec_id": r.spec_id, "reason_code": r.reason_code, "message": r.message} for r in prune_records],
    )

    return report


def main() -> None:
    parser = argparse.ArgumentParser(description="Layer1 自动化生成")
    parser.add_argument("--config", default="configs/api_lab_builder_step0.yaml")
    parser.add_argument("--output-dir", default="")
    args = parser.parse_args()

    config_path = BASE_DIR / args.config
    out_dir = (BASE_DIR / args.output_dir) if args.output_dir else None
    report = run_layer1_generate(config_path, out_dir)

    print("[Layer1] 完成")
    print(report)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Layer1 自动化生成：按算法条件组合生成基础稳定池。"""

from __future__ import annotations

import argparse
import itertools
import sys
from pathlib import Path
from typing import Any

BASE_DIR = Path(__file__).resolve().parents[2]
sys.path.insert(0, str(BASE_DIR))

from scripts.api_lab_builder.common import PruneRecord, append_jsonl, dedupe_key, dump_json, dump_yaml, load_yaml


def _product_dict(matrix: dict[str, list[Any]]) -> list[dict[str, Any]]:
    keys = list(matrix.keys())
    rows = []
    for values in itertools.product(*(matrix[k] for k in keys)):
        rows.append({k: v for k, v in zip(keys, values)})
    return rows


def _make_spec(algorithm: str, base: dict[str, Any], fixed: dict[str, Any], row: dict[str, Any]) -> dict[str, Any]:
    spec: dict[str, Any] = {
        "algorithm_stack": algorithm,
        "algo_params": {},
        "material_source": base.get("material_source"),
        "material_dynamicity": dict(base.get("material_dynamicity", {})),
        "validation_hops": fixed.get("validation_hops", "single_hop"),
        "anti_replay": row.get("anti_replay", "none"),
        "interlayers": list(fixed.get("interlayers", [])),
        "risk_tags": list(base.get("risk_tags", [])),
        "template_level": base.get("template_level", "BASELINE"),
    }

    if "session_policy" in base:
        spec["session_policy"] = dict(base["session_policy"])

    if algorithm == "PLAINTEXT_HMAC":
        placement = row.get("signature_placement") or base.get("signature_strategy", {}).get("placement")
        spec["signature_strategy"] = {"placement": placement}

    for key, value in row.items():
        if key in {"anti_replay", "signature_placement"}:
            continue
        spec["algo_params"][key] = value

    return spec


def _materialize_layer1_item(spec: dict[str, Any], cfg: dict[str, Any], seq: int) -> dict[str, Any]:
    item = dict(spec)
    item["algo_params"] = dict(spec.get("algo_params", {}))
    item["material_dynamicity"] = dict(spec.get("material_dynamicity", {}))
    item["risk_tags"] = list(spec.get("risk_tags", []))
    item["interlayers"] = list(spec.get("interlayers", []))
    if "signature_strategy" in spec:
        item["signature_strategy"] = dict(spec.get("signature_strategy", {}))
    if "session_policy" in spec:
        item["session_policy"] = dict(spec.get("session_policy", {}))

    # Layer1 不展开 2.7 路由维度，固定为基础路由，Layer5 再做翻倍展开。
    item["route_variant"] = "PLAIN_ROUTE"
    item["site_group"] = cfg["global"]["fixed_site_group"]
    item["id"] = f"layer1_{seq:05d}"
    return item


def _check_conflicts(spec: dict[str, Any], cfg: dict[str, Any]) -> list[PruneRecord]:
    errors: list[PruneRecord] = []
    spec_id = str(spec.get("id", "<unknown>"))
    algo = str(spec.get("algorithm_stack", ""))
    params = spec.get("algo_params", {}) if isinstance(spec.get("algo_params"), dict) else {}
    dynamic = spec.get("material_dynamicity", {}) if isinstance(spec.get("material_dynamicity"), dict) else {}
    anti_replay = str(spec.get("anti_replay", ""))
    signature_strategy = spec.get("signature_strategy", {}) if isinstance(spec.get("signature_strategy"), dict) else {}
    session_policy = spec.get("session_policy", {}) if isinstance(spec.get("session_policy"), dict) else {}

    # 兼容“原语链命名 + 历史命名”
    is_aes = algo in {"AES", "AES_CBC"}
    is_des = algo in {"DES", "DES_CBC"}
    is_rsa_only = algo == "RSA_ONLY"
    is_plain_hmac = algo == "PLAINTEXT_HMAC"

    # 字段唯一归属：algo_params 只能承载算法参数
    forbidden_param_keys = {
        "anti_replay",
        "material_source",
        "material_dynamicity",
        "signature_strategy",
        "session_policy",
        "signature_placement",
    }
    touched_forbidden = sorted(k for k in params.keys() if k in forbidden_param_keys)
    if touched_forbidden:
        errors.append(
            PruneRecord(
                spec_id,
                "CONFLICT_FIELD_OWNERSHIP_ALGO_PARAMS",
                f"algo_params 出现越权字段: {','.join(touched_forbidden)}",
            )
        )

    # signature_strategy 仅允许 coverage/placement
    invalid_sig_keys = sorted(k for k in signature_strategy.keys() if k not in {"coverage", "placement"})
    if invalid_sig_keys:
        errors.append(
            PruneRecord(
                spec_id,
                "CONFLICT_FIELD_OWNERSHIP_SIGNATURE_STRATEGY",
                f"signature_strategy 非法字段: {','.join(invalid_sig_keys)}",
            )
        )

    if algo not in set(cfg["global"]["algorithm_whitelist"]):
        errors.append(PruneRecord(spec_id, "SCHEMA_ALGO_NOT_ALLOWED", f"算法不在白名单: {algo}"))

    if str(spec.get("route_variant", "")) not in set(cfg["global"]["allowed_route_variants"]):
        errors.append(PruneRecord(spec_id, "SCHEMA_ROUTE_NOT_ALLOWED", "route_variant 不在允许集合"))

    if (is_aes or is_des) and str(params.get("mode", "")) == "":
        errors.append(PruneRecord(spec_id, "CONFLICT_SYMMETRIC_MODE_MISSING", "AES/DES 必须声明 mode"))

    if is_aes or is_des:
        mode = str(params.get("mode", "")).upper()
        if mode in {"CBC", "CFB", "OFB", "CTR"} and str(params.get("iv_policy", "absent")) == "absent":
            errors.append(
                PruneRecord(spec_id, "CONFLICT_SYMMETRIC_IV_ABSENT", "对称算法在该 mode 下要求 iv_policy != absent")
            )

    if is_rsa_only:
        blocked = [k for k in ["mode", "iv_policy", "padding"] if k in params]
        if blocked:
            errors.append(PruneRecord(spec_id, "CONFLICT_RSA_ONLY_SYMMETRIC_PARAMS", f"RSA_ONLY 禁止参数: {','.join(blocked)}"))

    if is_plain_hmac:
        blocked = [k for k in ["key_size", "mode", "iv_policy", "padding"] if k in params]
        if blocked:
            errors.append(
                PruneRecord(spec_id, "CONFLICT_HMAC_SYMMETRIC_PARAMS", f"PLAINTEXT_HMAC 禁止参数: {','.join(blocked)}")
            )

        placement = str(signature_strategy.get("placement", ""))
        if placement not in {"body", "header", "query"}:
            errors.append(PruneRecord(spec_id, "CONFLICT_HMAC_NO_PLACEMENT", "HMAC 需要签名放置位置"))

    def _dyn_missing(name: str) -> bool:
        return str(dynamic.get(name, "absent")) == "absent"

    if anti_replay == "timestamp_only" and _dyn_missing("timestamp"):
        errors.append(PruneRecord(spec_id, "CONFLICT_ANTI_REPLAY_TIMESTAMP_MISSING", "timestamp_only 缺少 timestamp"))

    if anti_replay == "nonce_only" and _dyn_missing("nonce"):
        errors.append(PruneRecord(spec_id, "CONFLICT_ANTI_REPLAY_NONCE_MISSING", "nonce_only 缺少 nonce"))

    if anti_replay == "nonce_timestamp":
        missing = [k for k in ["nonce", "timestamp"] if _dyn_missing(k)]
        if missing:
            errors.append(PruneRecord(spec_id, "CONFLICT_ANTI_REPLAY_NONCE_TIMESTAMP_MISSING", f"依赖缺失: {','.join(missing)}"))

    if anti_replay in {"nonce_timestamp_signature", "nonce_timestamp_signature_session_binding"}:
        missing = [k for k in ["nonce", "timestamp", "signature"] if _dyn_missing(k)]
        placement = str(signature_strategy.get("placement", ""))
        if placement not in {"body", "header", "query"}:
            missing.append("signature_placement")
        if anti_replay == "nonce_timestamp_signature_session_binding" and str(session_policy.get("binding", "")) != "bind_cookie":
            missing.append("session_binding")
        if missing:
            errors.append(PruneRecord(spec_id, "CONFLICT_ANTI_REPLAY_INCOMPLETE", f"依赖缺失: {','.join(missing)}"))

    if str(params.get("padding", "")) == "NoPadding" and not bool(params.get("plaintext_block_aligned", False)):
        errors.append(PruneRecord(spec_id, "CONFLICT_NOPADDING_ALIGNMENT", "NoPadding 需要块对齐"))

    if len(spec.get("interlayers", [])) > int(cfg["constraints"]["max_interlayers"]):
        errors.append(PruneRecord(spec_id, "CONFLICT_INTERLAYERS_OVERFLOW", "夹层层数超过上限"))

    if set(str(tag).upper() for tag in spec.get("risk_tags", [])) & set(
        str(tag).upper() for tag in cfg["constraints"].get("unsupported_markers", [])
    ):
        errors.append(PruneRecord(spec_id, "UNSUPPORTED_COMPLEX_CUSTOM_CRYPTO", "命中不支持复杂样本标记"))

    return errors


def run_layer1_generate(config_path: Path, output_dir: Path | None = None) -> dict[str, Any]:
    cfg = load_yaml(config_path)
    out_cfg = cfg["output"]
    out_root = output_dir or (BASE_DIR / out_cfg["directory"])
    out_root.mkdir(parents=True, exist_ok=True)

    fixed = cfg["layer1"]["fixed"]
    # 兼容新旧命名：优先原语链，兼容历史键
    order = ["AES", "AES_CBC", "DES", "DES_CBC", "RSA_ONLY", "AES_RSA_ENVELOPE", "PLAINTEXT_HMAC"]

    candidates: list[dict[str, Any]] = []
    seq = 1
    for algorithm in order:
        if algorithm not in cfg["layer1"]["algorithms"]:
            continue
        item = cfg["layer1"]["algorithms"][algorithm]
        base = item["base"]
        matrix = item["matrix"]
        for row in _product_dict(matrix):
            spec = _make_spec(algorithm, base, fixed, row)
            candidates.append(_materialize_layer1_item(spec, cfg, seq))
            seq += 1

    prune_records: list[PruneRecord] = []
    passed_conflict: list[dict[str, Any]] = []
    for spec in candidates:
        conflicts = _check_conflicts(spec, cfg)
        if conflicts:
            prune_records.extend(conflicts)
            continue
        passed_conflict.append(spec)

    selected: list[dict[str, Any]] = []
    seen: dict[str, str] = {}
    for spec in passed_conflict:
        key = dedupe_key(spec)
        spec["_dedupe_key"] = key
        if key in seen:
            prune_records.append(
                PruneRecord(spec["id"], "DUPLICATE_SPEC", f"与 {seen[key]} 去重键冲突")
            )
            continue
        seen[key] = spec["id"]
        selected.append(spec)

    reason_counts: dict[str, int] = {}
    for row in prune_records:
        reason_counts[row.reason_code] = reason_counts.get(row.reason_code, 0) + 1

    report = {
        "counts": {
            "generated_candidates": len(candidates),
            "after_conflict_prune": len(passed_conflict),
            "selected": len(selected),
            "pruned": len(prune_records),
        },
        "pruned_reason_counts": reason_counts,
        "gate": {
            "has_selected": len(selected) > 0,
        },
        "notes": {
            "layer": "Layer1",
            "model": "conditional_sum_product_then_prune",
            "execution_order": order,
        },
    }

    dump_yaml(out_root / out_cfg["layer1_pool_yaml"], selected)
    dump_json(out_root / out_cfg["layer1_pool_json"], selected)
    dump_json(out_root / out_cfg["layer1_gate_report"], report)
    append_jsonl(
        out_root / out_cfg["layer1_pruned_reasons"],
        [{"spec_id": r.spec_id, "reason_code": r.reason_code, "message": r.message} for r in prune_records],
    )

    return report


def main() -> None:
    parser = argparse.ArgumentParser(description="Layer1 自动化生成")
    parser.add_argument("--config", default="configs/api_lab_builder_step0.yaml")
    parser.add_argument("--output-dir", default="")
    args = parser.parse_args()

    config_path = BASE_DIR / args.config
    out_dir = (BASE_DIR / args.output_dir) if args.output_dir else None
    report = run_layer1_generate(config_path, out_dir)

    print("[Layer1] 完成")
    print(report)


if __name__ == "__main__":
    main()

