from scripts.api_lab_builder.common import dump_json, dump_yaml, load_yaml
PUBLIC_KEY_PEM = """-----BEGIN PUBLIC KEY----- MIGfMA0GCSqGSIb3DQEBAQUAA4GNADCBiQKBgQDRvA7giwinEkaTYllDYCkzujvi NH+up0XAKXQot8RixKGpB7nr8AdidEvuo+wVCxZwDK3hlcRGrrqt0Gxqwc11btlM DSj92Mr3xSaJcshZU8kfj325L8DRh9jpruphHBfh955ihvbednGAvOHOrz3Qy3Cb ocDbsNeCwNpRxwjIdQIDAQAB -----END PUBLIC KEY-----"""
PRIVATE_KEY_PEM = """-----BEGIN RSA PRIVATE KEY----- MIICXAIBAAKBgQDRvA7giwinEkaTYllDYCkzujviNH+up0XAKXQot8RixKGpB7nr 8AdidEvuo+wVCxZwDK3hlcRGrrqt0Gxqwc11btlMDSj92Mr3xSaJcshZU8kfj325 L8DRh9jpruphHBfh955ihvbednGAvOHOrz3Qy3CbocDbsNeCwNpRxwjIdQIDAQAB AoGAMek68RylFn025mQFMg90PqcXESHFMN8FrlEvH3F7/rUkc4EvMYKRf1CFsWi5 Cdj1ofyidIibiOaT7kEnS9CK//SmY+1628/eyngOvOR9ADsHN/JRlJ3dHathcBrr 1GENlCB9EmN+Fzhh7vEC2RUPrkkHCYGU2j+9rkzHUCXxLpECQQD5jgm9K7bvsOzM 82v6avdNFAV/9ILdple1xlCfcEuWgnRztxTS6fbVguDCkB95yQq/WT2XzuohUMSG 0uGGemlbAkEA1ya+aG8bRNlEC4yGiROSWZOiFBtiUhMyDGQ4E/FUifNdZSft5jSE gqUZZYJNchyKSXWtFKyclvJjcnflKxBubwJAT7eexs4bDvA+hK3RtVnMC9Q0eY5a 64ECja9++598leSwXHKEdWeFkOjQ8XXmiBm/lCZmtYLEacYKMWNV5YZe9wJAMYM/ CnWXRu7hE+9Q/ra8VVT+VbY/mDfGqsddiGlfVSfmdGMOAo5PeGlaQNwNypb61BD6 telLWAmMDUm+OXzcjQJBAJGn+vI0JV7OI0m4QpSucn/rJ9pAYJG4HE/MOQcgHog0 AeussmDIlr+wqWr+iJxYfJHc8ikTRSeTgqavruZs2Hg= -----END RSA PRIVATE KEY-----"""
def _algo_slug(algorithm: str) -> str: mapping = { "AES": "aes", "AES_CBC": "aes", "RSA_ONLY": "rsa", "PLAINTEXT_HMAC": "hmac", "DES": "des", "DES_CBC": "des", "AES_RSA_ENVELOPE": "aesrsa", } return mapping.get(algorithm, algorithm.lower())
def _group_by_algorithm(specs: list[dict[str, Any]]) -> dict[str, list[dict[str, Any]]]: grouped: dict[str, list[dict[str, Any]]] = {} for spec in specs: algo = str(spec.get("algorithm_stack", "UNKNOWN")) grouped.setdefault(algo, []).append(spec) return grouped
def _aes_key_len(key_size: int) -> int: if key_size <= 128: return 16 if key_size <= 192: return 24 return 32
def _seed(text: str, n: int) -> str: return (text * ((n // len(text)) + 1))[:n]
def _profile(spec: dict[str, Any]) -> dict[str, Any]: params = spec.get("algo_params", {}) if isinstance(spec.get("algo_params"), dict) else {} algo = str(spec.get("algorithm_stack", "")) key_size = int(params.get("key_size", 128)) if algo in {"DES", "DES_CBC"}: key_len = 8 else: key_len = _aes_key_len(key_size) iv_hex_len = 16 if algo in {"DES", "DES_CBC"} else 32 iv_utf8_len = 8 if algo in {"DES", "DES_CBC"} else 16 return { "algo": str(spec.get("algorithm_stack", "")), "anti_replay": str(spec.get("anti_replay", "none")), "key_size": key_size, "key_encoding": str(params.get("key_encoding", "utf8")), "iv_encoding": str(params.get("iv_encoding", "utf8")), "iv_policy": str(params.get("iv_policy", "static")), "padding": str(params.get("padding", "Pkcs7")), "signature_placement": str(spec.get("signature_strategy", {}).get("placement", "body")), "key_utf8": _seed("K", key_len), "iv_utf8": _seed("I", iv_utf8_len), "key_hex": _seed("ab", key_len * 2), "iv_hex": _seed("cd", iv_hex_len), "hmac_secret": "be56e057f20f883e", }
def _js_helpers() -> str: return ( "function __gen_parse_material(rawValue, encoding) {
" " if (encoding === 'hex') return CryptoJS.enc.Hex.parse(rawValue);
" " if (encoding === 'base64') return CryptoJS.enc.Base64.parse(rawValue);
" " return CryptoJS.enc.Utf8.parse(rawValue);
" "}

" "function __gen_nonce() {
" " return Math.random().toString(36).slice(2, 12);
" "}
" )
def _js_head(api_name: str, defaults: dict[str, Any]) -> list[str]: return [ f"async function {api_name}() {{", " const username = document.getElementById('username')?.value || '" + str(defaults.get("username", "test_user")) + "';", " const password = document.getElementById('password')?.value || '" + str(defaults.get("password", "test_pass")) + "';", " let nonce = null;", " let timestamp = null;", "", ]
def _js_replay(anti_replay: str) -> list[str]: rows: list[str] = [] if anti_replay in {"nonce_only", "nonce_timestamp"}: rows.append(" nonce = __gen_nonce();") if anti_replay in {"timestamp_only", "nonce_timestamp"}: rows.append(" timestamp = Math.floor(Date.now() / 1000);") if rows: rows.append("") return rows
def _render_js_aes(spec: dict[str, Any], endpoint: str, api_name: str, defaults: dict[str, Any]) -> str: p = _profile(spec) rows = _js_head(api_name, defaults) rows.extend( [ " const formData = { username: username, password: password };", " const jsonData = JSON.stringify(formData);", f" const key = __gen_parse_material('{p['key_hex'] if p['key_encoding'] == 'hex' else p['key_utf8']}', '{p['key_encoding']}');", " let iv = null;", ] ) if p["iv_policy"] == "random": rows.append(" iv = CryptoJS.lib.WordArray.random(16);") elif p["iv_policy"] == "derived": rows.extend( [ " const ivRaw = CryptoJS.SHA256(username).toString(CryptoJS.enc.Hex).slice(0, 32);", " iv = __gen_parse_material(ivRaw, 'hex');", ] ) else: iv_val = p["iv_hex"] if p["iv_encoding"] == "hex" else p["iv_utf8"] rows.append(f" iv = __gen_parse_material('{iv_val}', '{p['iv_encoding']}');")
rows.extend( [ " const encryptedData = CryptoJS.AES.encrypt(jsonData, key, {", " iv: iv,", " mode: CryptoJS.mode.CBC,", f" padding: CryptoJS.pad.{p['padding']}", " }).toString();", "", " const requestPayload = { encryptedData: encryptedData };", ] ) if p["iv_policy"] != "static": rows.append(" requestPayload.iv = iv.toString(CryptoJS.enc.Base64);")
rows.extend(_js_replay(p["anti_replay"])) rows.extend( [ " if (nonce) requestPayload.nonce = nonce;", " if (timestamp) requestPayload.timestamp = timestamp;", "", " const params = new URLSearchParams(requestPayload);", f" const response = await fetch('{endpoint}', {{", " method: 'POST',", " headers: { 'Content-Type': 'application/x-www-form-urlencoded; charset=utf-8' },", " body: params.toString()", " });", " const data = await response.json();", " if (data.success) alert('登录成功'); else alert(data.error || '用户名或密码错误');", "}", "", ] ) return "
".join(rows)
def _render_js_des(spec: dict[str, Any], endpoint: str, api_name: str, defaults: dict[str, Any]) -> str: p = _profile(spec) rows = _js_head(api_name, defaults) rows.extend( [ " const formData = { username: username, password: password };", " const jsonData = JSON.stringify(formData);", f" const key = __gen_parse_material('{p['key_hex'] if p['key_encoding'] == 'hex' else p['key_utf8']}', '{p['key_encoding']}');", " let iv = null;", ] ) iv_val = p["iv_hex"] if p["iv_encoding"] == "hex" else p["iv_utf8"] rows.append(f" iv = __gen_parse_material('{iv_val}', '{p['iv_encoding']}');") rows.extend( [ " const encryptedData = CryptoJS.DES.encrypt(jsonData, key, {", " iv: iv,", " mode: CryptoJS.mode.CBC,", " padding: CryptoJS.pad.Pkcs7", " }).toString();", "", " const requestPayload = { encryptedData: encryptedData };", ] ) rows.extend(_js_replay(p["anti_replay"])) rows.extend( [ " if (nonce) requestPayload.nonce = nonce;", " if (timestamp) requestPayload.timestamp = timestamp;", "", " const params = new URLSearchParams(requestPayload);", f" const response = await fetch('{endpoint}', {{", " method: 'POST',", " headers: { 'Content-Type': 'application/x-www-form-urlencoded; charset=utf-8' },", " body: params.toString()", " });", " const data = await response.json();", " if (data.success) alert('登录成功'); else alert(data.error || '用户名或密码错误');", "}", "", ] ) return "
".join(rows)
def _render_js_aes_rsa(spec: dict[str, Any], endpoint: str, api_name: str, defaults: dict[str, Any]) -> str: p = _profile(spec) rows = _js_head(api_name, defaults) rows.extend(_js_replay(p["anti_replay"])) rows.extend( [ " const formData = { username: username, password: password, nonce: nonce, timestamp: timestamp };", " const jsonData = JSON.stringify(formData);", " const aesKey = CryptoJS.lib.WordArray.random(16);", " const aesIv = CryptoJS.lib.WordArray.random(16);", " const encryptedData = CryptoJS.AES.encrypt(jsonData, aesKey, {", " iv: aesIv,", " mode: CryptoJS.mode.CBC,", f" padding: CryptoJS.pad.{p['padding']}", " }).toString();", " const encryptor = new JSEncrypt();", " encryptor.setPublicKey(`" + PUBLIC_KEY_PEM + "`);", " const encryptedKey = encryptor.encrypt(CryptoJS.enc.Base64.stringify(aesKey));", " const encryptedIv = encryptor.encrypt(CryptoJS.enc.Base64.stringify(aesIv));", " if (!encryptedKey || !encryptedIv) { alert('RSA 包裹失败'); return; }", " const requestPayload = { encryptedData, encryptedKey, encryptedIv };", " if (nonce) requestPayload.nonce = nonce;", " if (timestamp) requestPayload.timestamp = timestamp;", " const params = new URLSearchParams(requestPayload);", f" const response = await fetch('{endpoint}', {{", " method: 'POST',", " headers: { 'Content-Type': 'application/x-www-form-urlencoded; charset=utf-8' },", " body: params.toString()", " });", " const data = await response.json();", " if (data.success) alert('登录成功'); else alert(data.error || '用户名或密码错误');", "}", "", ] ) return "
".join(rows)
def _render_js_rsa(spec: dict[str, Any], endpoint: str, api_name: str, defaults: dict[str, Any]) -> str: p = _profile(spec) rows = _js_head(api_name, defaults) rows.extend(_js_replay(p["anti_replay"])) rows.extend( [ " const dataPacket = { username: username, password: password, nonce: nonce, timestamp: timestamp };", " const dataString = JSON.stringify(dataPacket);", " const encryptor = new JSEncrypt();", " encryptor.setPublicKey(`" + PUBLIC_KEY_PEM + "`);", " const encryptedData = encryptor.encrypt(dataString);", " if (!encryptedData) { alert('RSA 加密失败'); return; }", "", " const params = new URLSearchParams();", " params.append('data', encryptedData);", f" const response = await fetch('{endpoint}', {{", " method: 'POST',", " headers: { 'Content-Type': 'application/x-www-form-urlencoded; charset=utf-8' },", " body: params.toString()", " });", " const data = await response.json();", " if (data.success) alert('登录成功'); else alert(data.error || '用户名或密码错误');", "}", "", ] ) return "
".join(rows)
def _render_js_hmac(spec: dict[str, Any], endpoint: str, api_name: str, defaults: dict[str, Any]) -> str: p = _profile(spec) rows = _js_head(api_name, defaults) rows.extend(_js_replay(p["anti_replay"])) rows.extend( [ f" const secretKey = '{p['hmac_secret']}';", " const dataToSign = username + password + (nonce || '') + (timestamp || '');", " const signature = CryptoJS.HmacSHA256(dataToSign, secretKey).toString(CryptoJS.enc.Hex);", " const requestPayload = { username: username, password: password, nonce: nonce, timestamp: timestamp };", " const headers = { 'Content-Type': 'application/json; charset=utf-8' };", f" let requestUrl = '{endpoint}';", ] )
if p["signature_placement"] == "header": rows.append(" headers['X-Signature'] = signature;") elif p["signature_placement"] == "query": rows.append(" requestUrl += '?signature=' + encodeURIComponent(signature);") else: rows.append(" requestPayload.signature = signature;")
rows.extend( [ "", " const response = await fetch(requestUrl, {", " method: 'POST',", " headers: headers,", " body: JSON.stringify(requestPayload)", " });", " const data = await response.json();", " if (data.success) alert('登录成功'); else alert(data.error || '用户名或密码错误');", "}", "", ] ) return "
".join(rows)
def _render_js_function(spec: dict[str, Any], endpoint: str, api_name: str, defaults: dict[str, Any]) -> str: algo = str(spec.get("algorithm_stack", "")) if algo in {"AES", "AES_CBC"}: return _render_js_aes(spec, endpoint, api_name, defaults) if algo in {"DES", "DES_CBC"}: return _render_js_des(spec, endpoint, api_name, defaults) if algo == "RSA_ONLY": return _render_js_rsa(spec, endpoint, api_name, defaults) if algo == "AES_RSA_ENVELOPE": return _render_js_aes_rsa(spec, endpoint, api_name, defaults) if algo == "PLAINTEXT_HMAC": return _render_js_hmac(spec, endpoint, api_name, defaults) raise ValueError(f"Layer1 暂不支持写入算法: {algo}")
