def _render_php_endpoint(spec: dict[str, Any], api_name: str) -> str: algo = str(spec.get("algorithm_stack", "")) if algo in {"AES", "AES_CBC"}: return _php_aes(spec, api_name) if algo in {"DES", "DES_CBC"}: return _php_des(spec, api_name) if algo == "RSA_ONLY": return _php_rsa(spec, api_name) if algo == "AES_RSA_ENVELOPE": return _php_aes_rsa(spec, api_name) if algo == "PLAINTEXT_HMAC": return _php_hmac(spec, api_name) raise ValueError(f"Layer1 暂不支持写入算法: {algo}")
