            bridge_transform = "hex" if _derivation_requires_hex(derivation) else None

            candidate = None
            if "des.encrypt" in call_expr:
                for out_name, algo, _ in reversed(produced_outputs):
                    if algo == "DES":
                        candidate = out_name
                        break
            elif "aes.encrypt" in call_expr:
                for out_name, algo, _ in reversed(produced_outputs):
                    if algo == "AES":
                        candidate = out_name
                        break
